function normalizeTemplateTagsInput(rawValue) {
  const unique = new Set();
  const list = String(rawValue || '')
    .split(',')
    .map((item) => item.trim())
    .filter((item) => item.length > 0);
  list.forEach((item) => unique.add(item));
  return Array.from(unique).slice(0, 20);
}

async function getTeacherAssignedSubjects(userId) {
  if (!Number.isFinite(Number(userId))) return [];
  return db.all(
    `
      SELECT ts.subject_id, ts.group_number, s.name AS subject_name, s.group_count, s.is_general,
             s.course_id, c.name AS course_name
      FROM teacher_subjects ts
      JOIN subjects s ON s.id = ts.subject_id
      JOIN courses c ON c.id = s.course_id
      WHERE ts.user_id = ? AND s.visible = 1
      ORDER BY c.id, s.name, ts.group_number NULLS FIRST
    `,
    [userId]
  );
}

function buildTeacherCourseList(subjectRows = []) {
  const map = new Map();
  (subjectRows || []).forEach((row) => {
    const courseId = Number(row.course_id);
    if (!Number.isFinite(courseId) || courseId < 1 || map.has(courseId)) {
      return;
    }
    map.set(courseId, {
      id: courseId,
      name: String(row.course_name || `Course ${courseId}`),
    });
  });
  return Array.from(map.values()).sort((a, b) => Number(a.id) - Number(b.id));
}

async function getTeacherHomeworkTemplates(userId, options = {}) {
  if (!Number.isFinite(Number(userId))) return [];
  const requestedCourseId = Number(options.courseId);
  const scopedCourseId = Number.isInteger(requestedCourseId) && requestedCourseId > 0
    ? requestedCourseId
    : null;
  const requestedLimit = Number(options.limit);
  const limit = Number.isInteger(requestedLimit)
    ? Math.max(1, Math.min(requestedLimit, 500))
    : 200;
  const params = [Number(userId)];
  let where = 'WHERE t.user_id = ?';
  if (scopedCourseId) {
    where += ' AND (t.course_id IS NULL OR t.course_id = ?)';
    params.push(scopedCourseId);
  }
  const rows = await db.all(
    `
      SELECT
        t.*,
        s.name AS subject_name,
        c.name AS course_name
      FROM teacher_homework_templates t
      LEFT JOIN subjects s ON s.id = t.subject_id
      LEFT JOIN courses c ON c.id = COALESCE(t.course_id, s.course_id)
      ${where}
      ORDER BY t.updated_at DESC, t.id DESC
      LIMIT ${limit}
    `,
    params
  );
  return (rows || []).map((row) => {
    const tagItems = normalizeTemplateTagsInput(row.tags);
    return {
      id: Number(row.id),
      user_id: Number(row.user_id),
      course_id: Number.isFinite(Number(row.course_id)) ? Number(row.course_id) : null,
      subject_id: Number.isFinite(Number(row.subject_id)) ? Number(row.subject_id) : null,
      title: String(row.title || ''),
      description: String(row.description || ''),
      link_url: row.link_url ? String(row.link_url) : '',
      meeting_url: row.meeting_url ? String(row.meeting_url) : '',
      tags: tagItems.join(', '),
      tags_list: tagItems,
      is_control: row.is_control === true || Number(row.is_control) === 1 ? 1 : 0,
      is_credit: row.is_credit === true || Number(row.is_credit) === 1 ? 1 : 0,
      subject_name: row.subject_name ? String(row.subject_name) : '',
      course_name: row.course_name ? String(row.course_name) : '',
      created_at: row.created_at,
      updated_at: row.updated_at,
    };
  });
}

async function resolveTeacherTemplateScope(userId, requestedCourseIdRaw, requestedSubjectIdRaw) {
  const requestedCourseId = Number(requestedCourseIdRaw);
  const requestedSubjectId = Number(requestedSubjectIdRaw);
  let resolvedSubject = null;
  if (Number.isInteger(requestedSubjectId) && requestedSubjectId > 0) {
    resolvedSubject = await db.get(
      `
        SELECT s.id, s.course_id
        FROM teacher_subjects ts
        JOIN subjects s ON s.id = ts.subject_id
        WHERE ts.user_id = ? AND ts.subject_id = ?
        LIMIT 1
      `,
      [userId, requestedSubjectId]
    );
    if (!resolvedSubject) {
      return { ok: false, error: 'Invalid%20subject' };
    }
  }

  let validatedCourseId = null;
  if (Number.isInteger(requestedCourseId) && requestedCourseId > 0) {
    const hasCourseAccess = await db.get(
      `
        SELECT 1
        FROM teacher_subjects ts
        JOIN subjects s ON s.id = ts.subject_id
        WHERE ts.user_id = ? AND s.course_id = ?
        LIMIT 1
      `,
      [userId, requestedCourseId]
    );
    if (!hasCourseAccess) {
      return { ok: false, error: 'Invalid%20course' };
    }
    validatedCourseId = requestedCourseId;
  }

  if (
    resolvedSubject
    && validatedCourseId
    && Number(resolvedSubject.course_id) !== Number(validatedCourseId)
  ) {
    return { ok: false, error: 'Subject%20does%20not%20match%20course' };
  }

  const courseId = resolvedSubject
    ? Number(resolvedSubject.course_id)
    : (validatedCourseId || null);
  const subjectId = resolvedSubject ? Number(resolvedSubject.id) : null;
  return {
    ok: true,
    courseId,
    subjectId,
    validatedCourseId,
  };
}

function normalizeHomeworkTemplateTitleInput(rawTitle, fallbackDescription, fallbackSubjectName) {
  const clean = (value) => String(value || '').replace(/\s+/g, ' ').trim();
  const explicitTitle = clean(rawTitle);
  if (explicitTitle) {
    return explicitTitle.slice(0, 160);
  }
  const fallbackLine = clean(String(fallbackDescription || '').split('\n')[0]);
  if (fallbackLine) {
    return fallbackLine.slice(0, 160);
  }
  const subjectLabel = clean(fallbackSubjectName);
  if (subjectLabel) {
    return `${subjectLabel} homework`.slice(0, 160);
  }
  return 'Homework template';
}

async function maybeCreateTeacherTemplateFromHomework(req, payload = {}) {
  if (!req || !hasSessionRole(req, 'teacher')) {
    return null;
  }
  const shouldSave = ['1', 'true', 'on', 'yes'].includes(String((req.body && req.body.save_as_template) || '').toLowerCase());
  if (!shouldSave) {
    return null;
  }

  const userId = Number(payload.userId || req.session?.user?.id);
  const requestedCourseId = Number(payload.courseId);
  const requestedSubjectId = Number(payload.subjectId);
  const description = String(payload.description || '').trim();
  if (!Number.isInteger(userId) || userId < 1 || !Number.isInteger(requestedSubjectId) || requestedSubjectId < 1 || !description) {
    return null;
  }

  const title = normalizeHomeworkTemplateTitleInput(
    payload.title || (req.body && req.body.template_title),
    description,
    payload.subjectName
  );
  const tags = normalizeTemplateTagsInput(payload.tags).join(', ');
  const linkUrl = normalizeExternalUrl(payload.linkUrl) || null;
  const meetingUrl = normalizeExternalUrl(payload.meetingUrl) || null;
  const isControl = Number(payload.isControl) === 1 ? 1 : 0;
  const isCredit = Number(payload.isCredit) === 1 ? 1 : 0;

  try {
    const resolvedScope = await resolveTeacherTemplateScope(userId, requestedCourseId, requestedSubjectId);
    if (!resolvedScope.ok || !resolvedScope.subjectId) {
      return null;
    }
    const courseId = resolvedScope.courseId || null;
    const subjectId = resolvedScope.subjectId || null;
    const inserted = await db.get(
      `
        INSERT INTO teacher_homework_templates
          (course_id, subject_id, user_id, title, description, link_url, meeting_url, tags, is_control, is_credit, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
        RETURNING id
      `,
      [
        courseId,
        subjectId,
        userId,
        title,
        description,
        linkUrl,
        meetingUrl,
        tags,
        isControl,
        isCredit,
      ]
    );
    const templateId = inserted && inserted.id ? Number(inserted.id) : null;
    logAction(db, req, 'teacher_homework_template_create', {
      template_id: templateId,
      title,
      course_id: courseId,
      subject_id: subjectId,
      tags: tags ? tags.split(',').map((item) => item.trim()).filter(Boolean) : [],
      is_control: isControl,
      is_credit: isCredit,
      source: String(payload.source || 'homework_form'),
    });
    return templateId;
  } catch (err) {
    console.error('Teacher homework template auto-save failed', err);
    return null;
  }
}

async function saveTeacherSubjects(userId, body, options = {}) {
  const catalog = await getTeacherSubjectCatalog();
  const selections = [];
  let hasAny = false;
  for (const subject of catalog) {
    const selected = body[`subject_${subject.id}`];
    if (!selected) {
      continue;
    }
    hasAny = true;
    const isGeneral = subject.is_general === true || Number(subject.is_general) === 1;
    if (isGeneral) {
      selections.push({ subject_id: subject.id, group_number: null });
      continue;
    }
    const groupVal = body[`group_${subject.id}`];
    const groupNum = Number(groupVal);
    if (!groupVal || Number.isNaN(groupNum) || groupNum < 1 || groupNum > Number(subject.group_count || 1)) {
      return { ok: false, error: 'Select%20group' };
    }
    selections.push({ subject_id: subject.id, group_number: groupNum });
  }
  if (!hasAny) {
    return { ok: false, error: 'Select%20subject' };
  }
  await db.run('DELETE FROM teacher_subjects WHERE user_id = ?', [userId]);
  for (const item of selections) {
    await db.run(
      'INSERT INTO teacher_subjects (user_id, subject_id, group_number) VALUES (?, ?, ?)',
      [userId, item.subject_id, item.group_number]
    );
  }
  const existing = await db.get('SELECT status FROM teacher_requests WHERE user_id = ?', [userId]);
  let nextStatus = existing ? String(existing.status || 'pending') : 'pending';
  if (nextStatus === 'rejected') {
    nextStatus = 'pending';
  }
  if (existing) {
    if (nextStatus !== 'approved' || options.allowPendingReset) {
      await db.run(
        'UPDATE teacher_requests SET status = ?, updated_at = NOW() WHERE user_id = ?',
        [nextStatus, userId]
      );
    } else {
      await db.run('UPDATE teacher_requests SET updated_at = NOW() WHERE user_id = ?', [userId]);
    }
  } else {
    await db.run(
      'INSERT INTO teacher_requests (user_id, status) VALUES (?, ?)',
      [userId, nextStatus]
    );
  }
  return { ok: true, status: nextStatus, selections };
}

function broadcast(type, payload) {
  const message = JSON.stringify({ type, payload });
  wss.clients.forEach((client) => {
    if (client.readyState === 1) {
      client.send(message);
    }
  });
}

function sortSchedule(schedule, sortKey) {
  if (!sortKey) return schedule;
  const copy = [...schedule];
  if (sortKey === 'day') {
    const order = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
    copy.sort(
      (a, b) =>
        order.indexOf(a.day_of_week) - order.indexOf(b.day_of_week) || a.class_number - b.class_number
    );
  } else if (sortKey === 'time') {
    copy.sort((a, b) => a.class_number - b.class_number);
  } else if (sortKey === 'group') {
    copy.sort((a, b) => a.group_number - b.group_number || a.day_of_week.localeCompare(b.day_of_week));
  }
  return copy;
}

function sortHomework(homework, sortKey) {
  const normalized = (Array.isArray(homework) ? homework : []).map((item) => (
    item && item.file_name
      ? { ...item, file_name: normalizeUploadedOriginalName(item.file_name) }
      : item
  ));
  if (!sortKey) return normalized;
  const copy = [...normalized];
  if (sortKey === 'created') {
    copy.sort((a, b) => (a.created_at < b.created_at ? 1 : -1));
  } else if (sortKey === 'subject') {
    copy.sort((a, b) => a.subject.localeCompare(b.subject));
  }
  return copy;
}

