app.get('/teacher/workspace', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId, username } = req.session.user;
  const decodeMessage = (value) => {
    if (!value) return '';
    try {
      return decodeURIComponent(String(value));
    } catch (err) {
      return String(value);
    }
  };
  try {
    const teacherSubjects = await getTeacherAssignedSubjects(userId);
    const teacherCourses = buildTeacherCourseList(teacherSubjects);
    const requestedCourseId = Number(req.query.course);
    const selectedCourse = teacherCourses.find((course) => Number(course.id) === requestedCourseId) || null;
    const selectedCourseId = selectedCourse
      ? Number(selectedCourse.id)
      : (teacherCourses.length === 1 ? Number(teacherCourses[0].id) : null);

    const templates = await getTeacherHomeworkTemplates(userId, {
      courseId: selectedCourseId,
      limit: 300,
    });

    const subjectMap = new Map();
    teacherSubjects.forEach((subject) => {
      const subjectId = Number(subject.subject_id);
      if (!Number.isFinite(subjectId) || subjectId < 1 || subjectMap.has(subjectId)) return;
      subjectMap.set(subjectId, {
        id: subjectId,
        name: String(subject.subject_name || '').trim(),
        course_id: Number(subject.course_id),
        course_name: String(subject.course_name || ''),
      });
    });
    const allTeacherSubjects = Array.from(subjectMap.values()).sort((a, b) => {
      const byCourse = Number(a.course_id) - Number(b.course_id);
      if (byCourse !== 0) return byCourse;
      return String(a.name || '').localeCompare(String(b.name || ''), 'uk', { sensitivity: 'base' });
    });
    const scopedTeacherSubjects = selectedCourseId
      ? allTeacherSubjects.filter((subject) => Number(subject.course_id) === Number(selectedCourseId))
      : allTeacherSubjects;

    return res.render('teacher-workspace', {
      role: 'teacher',
      username,
      teacherCourses,
      selectedCourseId,
      teacherSubjects: scopedTeacherSubjects,
      teacherSubjectsAll: allTeacherSubjects,
      templates,
      error: decodeMessage(req.query.error),
      success: decodeMessage(req.query.ok),
    });
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace');
  }
});

app.post('/teacher/workspace/templates', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.create.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId, course_id: fallbackCourseId } = req.session.user;
  const title = String(req.body.title || '').trim();
  const description = String(req.body.description || '').trim();
  const requestedCourseId = Number(req.body.course_id);
  const requestedSubjectId = Number(req.body.subject_id);
  const isControl = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_control || '').toLowerCase()) ? 1 : 0;
  const isCredit = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_credit || '').toLowerCase()) ? 1 : 0;
  const tags = normalizeTemplateTagsInput(req.body.tags).join(', ');
  const linkUrl = normalizeExternalUrl(req.body.link_url) || null;
  const meetingUrl = normalizeExternalUrl(req.body.meeting_url) || null;

  if (!title || !description) {
    return res.redirect('/teacher/workspace?error=Title%20and%20description%20are%20required');
  }

  try {
    const resolvedScope = await resolveTeacherTemplateScope(userId, requestedCourseId, requestedSubjectId);
    if (!resolvedScope.ok) {
      return res.redirect(`/teacher/workspace?error=${resolvedScope.error || 'Invalid%20template%20scope'}`);
    }
    const { courseId, subjectId, validatedCourseId } = resolvedScope;

    const inserted = await db.get(
      `
        INSERT INTO teacher_homework_templates
          (
            user_id,
            course_id,
            subject_id,
            title,
            description,
            link_url,
            meeting_url,
            tags,
            is_control,
            is_credit,
            created_at,
            updated_at
          )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
        RETURNING id
      `,
      [
        userId,
        courseId,
        subjectId,
        title,
        description,
        linkUrl,
        meetingUrl,
        tags,
        isControl,
        isCredit,
      ]
    );

    logAction(db, req, 'teacher_homework_template_create', {
      template_id: inserted && inserted.id ? Number(inserted.id) : null,
      course_id: courseId,
      subject_id: subjectId,
      title,
      tags: tags ? tags.split(',').map((item) => item.trim()).filter(Boolean) : [],
      is_control: isControl,
      is_credit: isCredit,
    });

    const redirectCourseId = courseId || (validatedCourseId || null);
    const courseQuery = Number.isInteger(redirectCourseId) && redirectCourseId > 0
      ? `&course=${redirectCourseId}`
      : '';
    return res.redirect(`/teacher/workspace?ok=Template%20saved${courseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template create failed', err);
    const fallbackCourseQuery = Number.isInteger(requestedCourseId) && requestedCourseId > 0
      ? `&course=${requestedCourseId}`
      : (Number.isInteger(fallbackCourseId) && fallbackCourseId > 0 ? `&course=${fallbackCourseId}` : '');
    return res.redirect(`/teacher/workspace?error=Database%20error${fallbackCourseQuery}`);
  }
});

app.post('/teacher/workspace/templates/:id/update', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.update.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const templateId = Number(req.params.id);
  if (!Number.isInteger(templateId) || templateId < 1) {
    return res.redirect('/teacher/workspace?error=Invalid%20template');
  }

  const requestedCourseId = Number(req.body.course_id);
  const requestedSubjectId = Number(req.body.subject_id);
  const contextCourseId = Number(req.body.course_id_context);
  const fallbackCourseId = Number.isInteger(contextCourseId) && contextCourseId > 0
    ? contextCourseId
    : (Number.isInteger(requestedCourseId) && requestedCourseId > 0 ? requestedCourseId : null);
  const title = String(req.body.title || '').trim();
  const description = String(req.body.description || '').trim();
  const tags = normalizeTemplateTagsInput(req.body.tags).join(', ');
  const linkUrl = normalizeExternalUrl(req.body.link_url) || null;
  const meetingUrl = normalizeExternalUrl(req.body.meeting_url) || null;
  const isControl = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_control || '').toLowerCase()) ? 1 : 0;
  const isCredit = ['1', 'true', 'on', 'yes'].includes(String(req.body.is_credit || '').toLowerCase()) ? 1 : 0;
  const fallbackCourseQuery = fallbackCourseId ? `&course=${fallbackCourseId}` : '';

  if (!title || !description) {
    return res.redirect(`/teacher/workspace?error=Title%20and%20description%20are%20required${fallbackCourseQuery}`);
  }

  try {
    const existing = await db.get(
      `
        SELECT id, user_id, course_id, subject_id, title
        FROM teacher_homework_templates
        WHERE id = ?
        LIMIT 1
      `,
      [templateId]
    );
    if (!existing) {
      return res.redirect(`/teacher/workspace?error=Template%20not%20found${fallbackCourseQuery}`);
    }
    if (Number(existing.user_id) !== Number(userId)) {
      return res.status(403).send('Forbidden');
    }

    const resolvedScope = await resolveTeacherTemplateScope(userId, requestedCourseId, requestedSubjectId);
    if (!resolvedScope.ok) {
      return res.redirect(`/teacher/workspace?error=${resolvedScope.error || 'Invalid%20template%20scope'}${fallbackCourseQuery}`);
    }
    const { courseId, subjectId, validatedCourseId } = resolvedScope;

    await db.run(
      `
        UPDATE teacher_homework_templates
        SET
          course_id = ?,
          subject_id = ?,
          title = ?,
          description = ?,
          link_url = ?,
          meeting_url = ?,
          tags = ?,
          is_control = ?,
          is_credit = ?,
          updated_at = NOW()
        WHERE id = ?
      `,
      [
        courseId,
        subjectId,
        title,
        description,
        linkUrl,
        meetingUrl,
        tags,
        isControl,
        isCredit,
        templateId,
      ]
    );

    logAction(db, req, 'teacher_homework_template_update', {
      template_id: templateId,
      previous_title: existing.title ? String(existing.title) : '',
      title,
      course_id: courseId,
      subject_id: subjectId,
      tags: tags ? tags.split(',').map((item) => item.trim()).filter(Boolean) : [],
      is_control: isControl,
      is_credit: isCredit,
    });

    const redirectCourseId = courseId || validatedCourseId || fallbackCourseId || null;
    const courseQuery = redirectCourseId ? `&course=${redirectCourseId}` : '';
    return res.redirect(`/teacher/workspace?ok=Template%20updated${courseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template update failed', err);
    return res.redirect(`/teacher/workspace?error=Database%20error${fallbackCourseQuery}`);
  }
});

app.post('/teacher/workspace/templates/:id/clone', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.clone.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const templateId = Number(req.params.id);
  if (!Number.isInteger(templateId) || templateId < 1) {
    return res.redirect('/teacher/workspace?error=Invalid%20template');
  }
  const contextCourseId = Number(req.body.course_id_context);
  const fallbackCourseId = Number.isInteger(contextCourseId) && contextCourseId > 0 ? contextCourseId : null;
  const fallbackCourseQuery = fallbackCourseId ? `&course=${fallbackCourseId}` : '';
  const rawTargetSubjectIds = req.body.target_subject_ids;
  const targetSubjectIds = Array.from(
    new Set(
      (Array.isArray(rawTargetSubjectIds) ? rawTargetSubjectIds : [rawTargetSubjectIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 240);

  if (!targetSubjectIds.length) {
    return res.redirect(`/teacher/workspace?error=Select%20at%20least%20one%20subject${fallbackCourseQuery}`);
  }

  try {
    const sourceTemplate = await db.get(
      `
        SELECT
          id,
          user_id,
          course_id,
          subject_id,
          title,
          description,
          link_url,
          meeting_url,
          tags,
          is_control,
          is_credit
        FROM teacher_homework_templates
        WHERE id = ?
        LIMIT 1
      `,
      [templateId]
    );
    if (!sourceTemplate) {
      return res.redirect(`/teacher/workspace?error=Template%20not%20found${fallbackCourseQuery}`);
    }
    if (Number(sourceTemplate.user_id) !== Number(userId)) {
      return res.status(403).send('Forbidden');
    }

    const placeholders = targetSubjectIds.map(() => '?').join(', ');
    const rows = await db.all(
      `
        SELECT DISTINCT
          s.id AS subject_id,
          s.course_id,
          s.name AS subject_name,
          c.name AS course_name
        FROM teacher_subjects ts
        JOIN subjects s ON s.id = ts.subject_id
        LEFT JOIN courses c ON c.id = s.course_id
        WHERE ts.user_id = ?
          AND ts.subject_id IN (${placeholders})
      `,
      [userId, ...targetSubjectIds]
    );
    const targetMap = new Map();
    (rows || []).forEach((row) => {
      const subjectId = Number(row.subject_id);
      const courseId = Number(row.course_id);
      if (!Number.isInteger(subjectId) || subjectId < 1 || !Number.isInteger(courseId) || courseId < 1) {
        return;
      }
      if (!targetMap.has(subjectId)) {
        targetMap.set(subjectId, {
          subject_id: subjectId,
          course_id: courseId,
          subject_name: row.subject_name ? String(row.subject_name) : '',
          course_name: row.course_name ? String(row.course_name) : '',
        });
      }
    });
    if (!targetMap.size) {
      return res.redirect(`/teacher/workspace?error=Invalid%20subject%20selection${fallbackCourseQuery}`);
    }

    const sourceTitle = String(sourceTemplate.title || '').trim();
    const sourceDescription = String(sourceTemplate.description || '').trim();
    const sourceLinkUrl = sourceTemplate.link_url ? String(sourceTemplate.link_url) : null;
    const sourceMeetingUrl = sourceTemplate.meeting_url ? String(sourceTemplate.meeting_url) : null;
    const sourceTags = sourceTemplate.tags ? String(sourceTemplate.tags) : '';
    const sourceIsControl = sourceTemplate.is_control === true || Number(sourceTemplate.is_control) === 1 ? 1 : 0;
    const sourceIsCredit = sourceTemplate.is_credit === true || Number(sourceTemplate.is_credit) === 1 ? 1 : 0;

    let createdCount = 0;
    let duplicateCount = 0;
    for (const target of targetMap.values()) {
      const duplicate = await db.get(
        `
          SELECT id
          FROM teacher_homework_templates
          WHERE user_id = ?
            AND subject_id = ?
            AND COALESCE(course_id, 0) = COALESCE(?, 0)
            AND LOWER(title) = LOWER(?)
            AND COALESCE(description, '') = COALESCE(?, '')
          LIMIT 1
        `,
        [
          userId,
          Number(target.subject_id),
          Number(target.course_id),
          sourceTitle,
          sourceDescription,
        ]
      );
      if (duplicate) {
        duplicateCount += 1;
        continue;
      }

      const inserted = await db.get(
        `
          INSERT INTO teacher_homework_templates
            (user_id, course_id, subject_id, title, description, link_url, meeting_url, tags, is_control, is_credit, created_at, updated_at)
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
          RETURNING id
        `,
        [
          userId,
          Number(target.course_id),
          Number(target.subject_id),
          sourceTitle,
          sourceDescription,
          sourceLinkUrl,
          sourceMeetingUrl,
          sourceTags,
          sourceIsControl,
          sourceIsCredit,
        ]
      );
      if (inserted && inserted.id) {
        createdCount += 1;
      }
    }

    const invalidCount = Math.max(0, Number(targetSubjectIds.length) - Number(targetMap.size));
    logAction(db, req, 'teacher_homework_template_clone', {
      source_template_id: templateId,
      source_subject_id: sourceTemplate.subject_id ? Number(sourceTemplate.subject_id) : null,
      source_course_id: sourceTemplate.course_id ? Number(sourceTemplate.course_id) : null,
      created_count: createdCount,
      duplicate_count: duplicateCount,
      invalid_count: invalidCount,
      target_subject_ids: Array.from(targetMap.keys()),
    });

    const suffixes = [];
    if (duplicateCount > 0) {
      suffixes.push(`${duplicateCount} duplicates skipped`);
    }
    if (invalidCount > 0) {
      suffixes.push(`${invalidCount} invalid selections skipped`);
    }
    const baseMessage = createdCount > 0
      ? `Template cloned to ${createdCount} subject${createdCount === 1 ? '' : 's'}`
      : 'No templates were cloned';
    const fullMessage = suffixes.length ? `${baseMessage} (${suffixes.join(', ')})` : baseMessage;
    const redirectCourseId = fallbackCourseId
      || (Number.isInteger(Number(sourceTemplate.course_id)) && Number(sourceTemplate.course_id) > 0
        ? Number(sourceTemplate.course_id)
        : null);
    const courseQuery = redirectCourseId ? `&course=${redirectCourseId}` : '';
    return res.redirect(`/teacher/workspace?ok=${encodeURIComponent(fullMessage)}${courseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template clone failed', err);
    return res.redirect(`/teacher/workspace?error=Database%20error${fallbackCourseQuery}`);
  }
});

app.post('/teacher/workspace/templates/bulk-clone', requireLogin, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'teacher.workspace.templates.bulkClone.init');
  }
  if (!hasSessionRole(req, 'teacher')) {
    return res.redirect('/schedule');
  }
  const { id: userId } = req.session.user;
  const contextCourseId = Number(req.body.course_id_context);
  const fallbackCourseId = Number.isInteger(contextCourseId) && contextCourseId > 0 ? contextCourseId : null;
  const fallbackCourseQuery = fallbackCourseId ? `&course=${fallbackCourseId}` : '';
  const rawSourceTemplateIds = req.body.source_template_ids;
  const sourceTemplateIds = Array.from(
    new Set(
      (Array.isArray(rawSourceTemplateIds) ? rawSourceTemplateIds : [rawSourceTemplateIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 120);
  const rawTargetSubjectIds = req.body.target_subject_ids;
  const targetSubjectIds = Array.from(
    new Set(
      (Array.isArray(rawTargetSubjectIds) ? rawTargetSubjectIds : [rawTargetSubjectIds])
        .map((value) => Number(value))
        .filter((value) => Number.isInteger(value) && value > 0)
    )
  ).slice(0, 240);

  if (!sourceTemplateIds.length || !targetSubjectIds.length) {
    return res.redirect(`/teacher/workspace?error=Select%20templates%20and%20subjects%20for%20bulk%20clone${fallbackCourseQuery}`);
  }

  try {
    const sourcePlaceholders = sourceTemplateIds.map(() => '?').join(', ');
    const sourceRows = await db.all(
      `
        SELECT
          id,
          user_id,
          course_id,
          subject_id,
          title,
          description,
          link_url,
          meeting_url,
          tags,
          is_control,
          is_credit
        FROM teacher_homework_templates
        WHERE user_id = ?
          AND id IN (${sourcePlaceholders})
        ORDER BY updated_at DESC, id DESC
      `,
      [userId, ...sourceTemplateIds]
    );
    if (!sourceRows.length) {
      return res.redirect(`/teacher/workspace?error=No%20source%20templates%20found${fallbackCourseQuery}`);
    }

    const targetPlaceholders = targetSubjectIds.map(() => '?').join(', ');
    const targetRows = await db.all(
      `
        SELECT DISTINCT
          s.id AS subject_id,
          s.course_id,
          s.name AS subject_name,
          c.name AS course_name
        FROM teacher_subjects ts
        JOIN subjects s ON s.id = ts.subject_id
        LEFT JOIN courses c ON c.id = s.course_id
        WHERE ts.user_id = ?
          AND ts.subject_id IN (${targetPlaceholders})
      `,
      [userId, ...targetSubjectIds]
    );
    const targetMap = new Map();
    (targetRows || []).forEach((row) => {
      const subjectId = Number(row.subject_id);
      const courseId = Number(row.course_id);
      if (!Number.isInteger(subjectId) || subjectId < 1 || !Number.isInteger(courseId) || courseId < 1) {
        return;
      }
      if (!targetMap.has(subjectId)) {
        targetMap.set(subjectId, {
          subject_id: subjectId,
          course_id: courseId,
          subject_name: row.subject_name ? String(row.subject_name) : '',
          course_name: row.course_name ? String(row.course_name) : '',
        });
      }
    });
    if (!targetMap.size) {
      return res.redirect(`/teacher/workspace?error=Invalid%20target%20subjects${fallbackCourseQuery}`);
    }

    let createdCount = 0;
    let duplicateCount = 0;
    for (const source of sourceRows) {
      const sourceTitle = String(source.title || '').trim();
      const sourceDescription = String(source.description || '').trim();
      const sourceLinkUrl = source.link_url ? String(source.link_url) : null;
      const sourceMeetingUrl = source.meeting_url ? String(source.meeting_url) : null;
      const sourceTags = source.tags ? String(source.tags) : '';
      const sourceIsControl = source.is_control === true || Number(source.is_control) === 1 ? 1 : 0;
      const sourceIsCredit = source.is_credit === true || Number(source.is_credit) === 1 ? 1 : 0;

      for (const target of targetMap.values()) {
        const duplicate = await db.get(
          `
            SELECT id
            FROM teacher_homework_templates
            WHERE user_id = ?
              AND subject_id = ?
              AND COALESCE(course_id, 0) = COALESCE(?, 0)
              AND LOWER(title) = LOWER(?)
              AND COALESCE(description, '') = COALESCE(?, '')
            LIMIT 1
          `,
          [
            userId,
            Number(target.subject_id),
            Number(target.course_id),
            sourceTitle,
            sourceDescription,
          ]
        );
        if (duplicate) {
          duplicateCount += 1;
          continue;
        }

        const inserted = await db.get(
          `
            INSERT INTO teacher_homework_templates
              (user_id, course_id, subject_id, title, description, link_url, meeting_url, tags, is_control, is_credit, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW(), NOW())
            RETURNING id
          `,
          [
            userId,
            Number(target.course_id),
            Number(target.subject_id),
            sourceTitle,
            sourceDescription,
            sourceLinkUrl,
            sourceMeetingUrl,
            sourceTags,
            sourceIsControl,
            sourceIsCredit,
          ]
        );
        if (inserted && inserted.id) {
          createdCount += 1;
        }
      }
    }

    const invalidSourceCount = Math.max(0, sourceTemplateIds.length - sourceRows.length);
    const invalidTargetCount = Math.max(0, targetSubjectIds.length - targetMap.size);
    logAction(db, req, 'teacher_homework_template_bulk_clone', {
      source_template_ids: sourceRows.map((row) => Number(row.id)).filter((value) => Number.isInteger(value) && value > 0),
      target_subject_ids: Array.from(targetMap.keys()),
      source_count: sourceRows.length,
      target_count: targetMap.size,
      created_count: createdCount,
      duplicate_count: duplicateCount,
      invalid_source_count: invalidSourceCount,
      invalid_target_count: invalidTargetCount,
    });

    const suffixes = [];
    if (duplicateCount > 0) {
      suffixes.push(`${duplicateCount} duplicates skipped`);
    }
    if (invalidSourceCount > 0) {
      suffixes.push(`${invalidSourceCount} missing sources skipped`);
    }
    if (invalidTargetCount > 0) {
      suffixes.push(`${invalidTargetCount} invalid targets skipped`);
    }
    const baseMessage = createdCount > 0
      ? `Bulk clone created ${createdCount} template copies`
      : 'Bulk clone created no new templates';
    const scopeMessage = ` from ${sourceRows.length} source template${sourceRows.length === 1 ? '' : 's'} to ${targetMap.size} subject${targetMap.size === 1 ? '' : 's'}`;
    const fullMessage = suffixes.length
      ? `${baseMessage}${scopeMessage} (${suffixes.join(', ')})`
      : `${baseMessage}${scopeMessage}`;
    return res.redirect(`/teacher/workspace?ok=${encodeURIComponent(fullMessage)}${fallbackCourseQuery}`);
  } catch (err) {
    console.error('Teacher workspace template bulk clone failed', err);
    return res.redirect(`/teacher/workspace?error=Database%20error${fallbackCourseQuery}`);
  }
});

