const SESSION_GENERATOR_DEFAULTS = {
  window_mode: 'weeks',
  session_days: 14,
  session_weeks_count: 2,
  session_weeks_set: '',
  max_events_per_day: 3,
  reserve_every: 0,
  exam_gap_days: 0,
  retake_gap_days: 2,
  retake_window_days: 3,
  include_weekends: false,
  include_consultations: false,
  respect_study_days: false,
  day_grouping_mode: 'none',
  exam_sequence: 'exam_only',
  credit_sequence: 'credit_only',
  strategy: 'balanced',
};

const SESSION_GENERATOR_DRAFTS_LIMIT = 12;
const SESSION_GENERATOR_DRAFTS_MAX_ASSIGNMENTS = 2000;
const SESSION_GENERATOR_FORM_QUERY_KEYS = new Set([
  'window_mode',
  'start_date',
  'session_days',
  'session_weeks_count',
  'session_weeks_set',
  'max_events_per_day',
  'reserve_every',
  'exam_gap_days',
  'retake_gap_days',
  'retake_window_days',
  'include_weekends',
  'include_consultations',
  'respect_study_days',
  'day_grouping_mode',
  'exam_sequence',
  'credit_sequence',
  'strategy',
]);

const hasOwnQueryKey = (obj, key) => Object.prototype.hasOwnProperty.call(obj || {}, key);

const normalizeSessionGeneratorDraftForm = (rawValue, fallback = {}) => {
  let payload = rawValue;
  if (payload === undefined || payload === null || payload === '') {
    return { ...(fallback || {}) };
  }
  if (typeof payload === 'string') {
    const trimmed = payload.trim();
    if (!trimmed) return { ...(fallback || {}) };
    try {
      payload = JSON.parse(trimmed);
    } catch (_err) {
      return { ...(fallback || {}) };
    }
  }
  if (!payload || Array.isArray(payload) || typeof payload !== 'object') {
    return { ...(fallback || {}) };
  }
  const normalized = { ...(fallback || {}) };
  Object.entries(payload).forEach(([key, value]) => {
    const safeKey = String(key || '');
    if (
      SESSION_GENERATOR_FORM_QUERY_KEYS.has(safeKey)
      || safeKey === 'location'
      || safeKey === 'course_id'
      || safeKey === 'semester_id'
    ) {
      normalized[safeKey] = value;
    }
  });
  return normalized;
};

const normalizeSessionGeneratorDraftAssignments = (rawValue) =>
  parseSessionManualAssignments(rawValue).slice(0, SESSION_GENERATOR_DRAFTS_MAX_ASSIGNMENTS);

const mapSessionGeneratorDraftRow = (row) => {
  if (!row) return null;
  const id = Number(row.id);
  if (!Number.isFinite(id) || id < 1) return null;
  return {
    id,
    user_id: Number(row.user_id || 0) || null,
    location: normalizeGeneratorLocation(row.location || 'kyiv'),
    course_id: Number.isFinite(Number(row.course_id)) && Number(row.course_id) > 0 ? Number(row.course_id) : null,
    semester_id: Number.isFinite(Number(row.semester_id)) && Number(row.semester_id) > 0 ? Number(row.semester_id) : null,
    created_at: row.created_at || null,
    updated_at: row.updated_at || null,
    form: normalizeSessionGeneratorDraftForm(row.form_json, {}),
    assignments: normalizeSessionGeneratorDraftAssignments(row.assignments_json),
  };
};

const pruneSessionGeneratorDraftRecords = async (userId) => {
  const safeUserId = Number(userId);
  if (!Number.isFinite(safeUserId) || safeUserId < 1) return;
  await db.run(
    `
      DELETE FROM session_generator_drafts
      WHERE user_id = ?
        AND id IN (
          SELECT id
          FROM session_generator_drafts
          WHERE user_id = ?
          ORDER BY updated_at DESC, id DESC
          OFFSET ?
        )
    `,
    [safeUserId, safeUserId, SESSION_GENERATOR_DRAFTS_LIMIT]
  );
};

const listSessionGeneratorDraftRecords = async (userId) => {
  const safeUserId = Number(userId);
  if (!Number.isFinite(safeUserId) || safeUserId < 1) return [];
  const rows = await db.all(
    `
      SELECT id, user_id, location, course_id, semester_id, form_json, assignments_json, created_at, updated_at
      FROM session_generator_drafts
      WHERE user_id = ?
      ORDER BY updated_at DESC, id DESC
      LIMIT ?
    `,
    [safeUserId, SESSION_GENERATOR_DRAFTS_LIMIT]
  );
  return (rows || [])
    .map((row) => mapSessionGeneratorDraftRow(row))
    .filter(Boolean);
};

const getSessionGeneratorDraftRecordById = async (userId, draftId) => {
  const safeUserId = Number(userId);
  const safeDraftId = Number(draftId);
  if (!Number.isFinite(safeUserId) || safeUserId < 1 || !Number.isFinite(safeDraftId) || safeDraftId < 1) {
    return null;
  }
  const row = await db.get(
    `
      SELECT id, user_id, location, course_id, semester_id, form_json, assignments_json, created_at, updated_at
      FROM session_generator_drafts
      WHERE id = ? AND user_id = ?
      LIMIT 1
    `,
    [safeDraftId, safeUserId]
  );
  return mapSessionGeneratorDraftRow(row);
};

const createSessionGeneratorDraftRecord = async (userId, seedForm = {}, seedAssignments = []) => {
  const safeUserId = Number(userId);
  if (!Number.isFinite(safeUserId) || safeUserId < 1) return null;
  const baseForm = normalizeSessionGeneratorDraftForm(seedForm, {});
  const location = normalizeGeneratorLocation(baseForm.location || 'kyiv');
  const courseId = parseSessionGeneratorInt(baseForm.course_id, null, 1, Number.MAX_SAFE_INTEGER);
  const semesterId = parseSessionGeneratorInt(baseForm.semester_id, null, 1, Number.MAX_SAFE_INTEGER);
  const formPayload = {
    ...baseForm,
    location,
    course_id: courseId,
    semester_id: semesterId,
  };
  const assignmentsPayload = normalizeSessionGeneratorDraftAssignments(seedAssignments);
  const row = await db.get(
    `
      INSERT INTO session_generator_drafts
        (user_id, location, course_id, semester_id, form_json, assignments_json, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, ?, NOW(), NOW())
      RETURNING id, user_id, location, course_id, semester_id, form_json, assignments_json, created_at, updated_at
    `,
    [
      safeUserId,
      location,
      courseId || null,
      semesterId || null,
      JSON.stringify(formPayload),
      JSON.stringify(assignmentsPayload),
    ]
  );
  await pruneSessionGeneratorDraftRecords(safeUserId);
  return mapSessionGeneratorDraftRow(row);
};

const saveSessionGeneratorDraftRecord = async (userId, draftId, payload = {}) => {
  const safeUserId = Number(userId);
  const safeDraftId = Number(draftId);
  if (!Number.isFinite(safeUserId) || safeUserId < 1 || !Number.isFinite(safeDraftId) || safeDraftId < 1) {
    return null;
  }
  const current = await getSessionGeneratorDraftRecordById(safeUserId, safeDraftId);
  if (!current) return null;
  const form = normalizeSessionGeneratorDraftForm(
    payload && hasOwnQueryKey(payload, 'form') ? payload.form : current.form,
    current.form
  );
  const location = normalizeGeneratorLocation(form.location || current.location || 'kyiv');
  const courseId = parseSessionGeneratorInt(form.course_id, current.course_id, 1, Number.MAX_SAFE_INTEGER);
  const semesterId = parseSessionGeneratorInt(form.semester_id, current.semester_id, 1, Number.MAX_SAFE_INTEGER);
  const assignments = payload && hasOwnQueryKey(payload, 'assignments')
    ? normalizeSessionGeneratorDraftAssignments(payload.assignments)
    : normalizeSessionGeneratorDraftAssignments(current.assignments);
  const formPayload = {
    ...form,
    location,
    course_id: courseId,
    semester_id: semesterId,
  };
  const row = await db.get(
    `
      UPDATE session_generator_drafts
      SET
        location = ?,
        course_id = ?,
        semester_id = ?,
        form_json = ?,
        assignments_json = ?,
        updated_at = NOW()
      WHERE id = ? AND user_id = ?
      RETURNING id, user_id, location, course_id, semester_id, form_json, assignments_json, created_at, updated_at
    `,
    [
      location,
      courseId || null,
      semesterId || null,
      JSON.stringify(formPayload),
      JSON.stringify(assignments),
      safeDraftId,
      safeUserId,
    ]
  );
  await pruneSessionGeneratorDraftRecords(safeUserId);
  return mapSessionGeneratorDraftRow(row);
};

const buildSessionGeneratorFormDefaults = ({ activeLocation, selectedCourseId, selectedSemesterId, defaultStartDate }) => ({
  location: normalizeGeneratorLocation(activeLocation),
  course_id: Number.isFinite(Number(selectedCourseId)) && Number(selectedCourseId) > 0 ? Number(selectedCourseId) : null,
  semester_id: Number.isFinite(Number(selectedSemesterId)) && Number(selectedSemesterId) > 0 ? Number(selectedSemesterId) : null,
  window_mode: SESSION_GENERATOR_DEFAULTS.window_mode,
  start_date: defaultStartDate,
  session_days: SESSION_GENERATOR_DEFAULTS.session_days,
  session_weeks_count: SESSION_GENERATOR_DEFAULTS.session_weeks_count,
  session_weeks_set: SESSION_GENERATOR_DEFAULTS.session_weeks_set,
  max_events_per_day: SESSION_GENERATOR_DEFAULTS.max_events_per_day,
  reserve_every: SESSION_GENERATOR_DEFAULTS.reserve_every,
  exam_gap_days: SESSION_GENERATOR_DEFAULTS.exam_gap_days,
  retake_gap_days: SESSION_GENERATOR_DEFAULTS.retake_gap_days,
  retake_window_days: SESSION_GENERATOR_DEFAULTS.retake_window_days,
  include_weekends: SESSION_GENERATOR_DEFAULTS.include_weekends,
  include_consultations: SESSION_GENERATOR_DEFAULTS.include_consultations,
  respect_study_days: SESSION_GENERATOR_DEFAULTS.respect_study_days,
  day_grouping_mode: SESSION_GENERATOR_DEFAULTS.day_grouping_mode,
  exam_sequence: SESSION_GENERATOR_DEFAULTS.exam_sequence,
  credit_sequence: SESSION_GENERATOR_DEFAULTS.credit_sequence,
  strategy: SESSION_GENERATOR_DEFAULTS.strategy,
});

const hasSessionGeneratorFormPayload = (query) =>
  Object.keys(query || {}).some((key) => SESSION_GENERATOR_FORM_QUERY_KEYS.has(String(key)));

const normalizeSessionWindowMode = (value) => {
  const raw = String(value || '').trim().toLowerCase();
  return raw === 'weeks' ? 'weeks' : 'days';
};

const normalizeSessionDayGroupingMode = (value) => {
  const raw = String(value || '').trim().toLowerCase();
  if (raw === 'subject_per_day') return 'subject_per_day';
  if (raw === 'activity_per_day') return 'activity_per_day';
  return 'none';
};

const normalizeSessionExamSequence = (value) => {
  const raw = String(value || '').trim().toLowerCase();
  if (raw === 'exam_only') return 'exam_only';
  if (raw === 'consult_exam_credit') return 'consult_exam_credit';
  return 'consult_exam';
};

const normalizeSessionCreditSequence = (value) => {
  const raw = String(value || '').trim().toLowerCase();
  if (raw === 'consult_credit') return 'consult_credit';
  return 'credit_only';
};

const normalizeSessionGeneratorStrategy = (value) => {
  const raw = String(value || '').trim().toLowerCase();
  if (raw === 'credits_first') return 'credits_first';
  if (raw === 'balanced') return 'balanced';
  return 'exams_first';
};

const parseSessionGeneratorFlag = (value, fallback = false) => {
  if (value === undefined || value === null || value === '') return !!fallback;
  const raw = String(value).trim().toLowerCase();
  if (['1', 'true', 't', 'yes', 'on'].includes(raw)) return true;
  if (['0', 'false', 'f', 'no', 'off'].includes(raw)) return false;
  return !!fallback;
};

const parseSessionGeneratorInt = (value, fallback, min, max) => {
  if (value === undefined || value === null || String(value).trim() === '') return fallback;
  const num = Number(value);
  if (!Number.isFinite(num)) return fallback;
  const rounded = Math.round(num);
  if (Number.isFinite(min) && rounded < min) return min;
  if (Number.isFinite(max) && rounded > max) return max;
  return rounded;
};

const parseSessionManualAssignments = (rawValue) => {
  if (rawValue === undefined || rawValue === null || rawValue === '') return [];
  let payload = rawValue;
  if (typeof payload === 'string') {
    const trimmed = payload.trim();
    if (!trimmed) return [];
    try {
      payload = JSON.parse(trimmed);
    } catch (_err) {
      return [];
    }
  }
  if (!Array.isArray(payload)) return [];
  return payload
    .slice(0, 2000)
    .map((row) => {
      const subjectId = Number(row && row.subject_id);
      const classNumber = Number(row && row.class_number);
      const typeRaw = String(row && row.type ? row.type : '').trim().toLowerCase();
      let type = '';
      if (typeRaw === 'credit') type = 'credit';
      if (typeRaw === 'exam') type = 'exam';
      if (typeRaw === 'consultation' || typeRaw === 'consult' || typeRaw === 'cons') type = 'consultation';
      const date = row && row.date ? String(row.date).slice(0, 10) : '';
      const groupNumberRaw = Number(row && row.group_number);
      const groupNumber = Number.isFinite(groupNumberRaw) && groupNumberRaw > 0
        ? Math.floor(groupNumberRaw)
        : null;
      const note = row && row.note ? String(row.note).trim().slice(0, 255) : '';
      if (!Number.isFinite(subjectId) || subjectId < 1) return null;
      if (!Number.isFinite(classNumber) || classNumber < 1 || classNumber > 7) return null;
      if (!type) return null;
      if (!date || !isValidDateString(date)) return null;
      return {
        subject_id: Math.floor(subjectId),
        class_number: Math.floor(classNumber),
        type,
        date,
        group_number: groupNumber,
        note,
      };
    })
    .filter(Boolean);
};

const parseIsoDateList = (rawValue, limit = 180) => {
  if (rawValue === undefined || rawValue === null || rawValue === '') return [];
  let payload = rawValue;
  if (typeof payload === 'string') {
    const trimmed = payload.trim();
    if (!trimmed) return [];
    try {
      payload = JSON.parse(trimmed);
    } catch (_err) {
      payload = trimmed.split(',');
    }
  }
  if (!Array.isArray(payload)) return [];
  const dates = payload
    .slice(0, Math.max(1, Number(limit) || 1))
    .map((value) => String(value || '').slice(0, 10))
    .filter((value) => isValidDateString(value));
  return Array.from(new Set(dates)).sort();
};

const toIsoDateOnly = (value) => {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return null;
  return new Date(Date.UTC(date.getUTCFullYear(), date.getUTCMonth(), date.getUTCDate()))
    .toISOString()
    .slice(0, 10);
};

const addDaysIso = (isoDate, days) => {
  if (!isoDate || !isValidDateString(isoDate)) return null;
  const next = addDays(new Date(`${isoDate}T00:00:00Z`), Number(days) || 0);
  return toIsoDateOnly(next);
};

const diffDaysIso = (a, b) => {
  if (!a || !b || !isValidDateString(a) || !isValidDateString(b)) return null;
  const aUtc = parseDateUTC(a);
  const bUtc = parseDateUTC(b);
  if (aUtc === null || bUtc === null) return null;
  return Math.round((aUtc - bUtc) / (24 * 60 * 60 * 1000));
};

const getStudyDayShortLabel = (dayName) => {
  const idx = fullWeekDays.indexOf(dayName);
  return idx >= 0 ? (studyDayLabels[idx] || dayName) : dayName;
};

const buildSessionGeneratorDefaultStartDate = (semester) => {
  if (semester && semester.start_date && isValidDateString(semester.start_date)) {
    const weeks = Math.max(1, Number(semester.weeks_count || 15));
    return addDaysIso(semester.start_date, weeks * 7);
  }
  return toIsoDateOnly(new Date());
};

const safeArrayChunk = (list, size) => {
  const normalizedSize = Math.max(1, Number(size) || 1);
  const result = [];
  for (let i = 0; i < list.length; i += normalizedSize) {
    result.push(list.slice(i, i + normalizedSize));
  }
  return result;
};

const shuffleArrayDeterministic = (items, seed = 1) => {
  const list = [...items];
  let x = Number(seed) || 1;
  for (let i = list.length - 1; i > 0; i -= 1) {
    x = (x * 1664525 + 1013904223) % 4294967296;
    const j = x % (i + 1);
    [list[i], list[j]] = [list[j], list[i]];
  }
  return list;
};

const buildSessionAssessmentPlan = ({ subjects = [], gradingBySubject = {} }) => {
  const sourceRows = [];
  const queue = [];
  const groupUpperCap = 6;
  (subjects || []).forEach((subject) => {
    const subjectId = Number(subject.id);
    const grading = gradingBySubject[subjectId] || {};
    const examEnabled = Number(grading.exam_enabled ?? 1) === 1;
    const creditEnabled = Number(grading.credit_enabled ?? 1) === 1;
    const examWeight = Number(grading.exam_weight_points ?? 0) || 0;
    const creditWeight = Number(grading.credit_weight_points ?? 0) || 0;
    const isRequired = !(subject.is_required === false || Number(subject.is_required) === 0);
    const isGeneral = subject.is_general === true || Number(subject.is_general) === 1;
    const groupCountRaw = Math.max(1, Number(subject.group_count || 1));
    const groupCount = Math.min(groupUpperCap, groupCountRaw);
    const lowered = String(subject.name || '').toLowerCase();
    const looksLikePractice = /(семінар|семинар|practice|практик|lab|лаборатор)/i.test(lowered);
    let assessmentType = 'exam';
    let typeReason = 'fallback_required_subject';
    if (examEnabled && !creditEnabled) {
      assessmentType = 'exam';
      typeReason = 'grading_exam_enabled_only';
    } else if (!examEnabled && creditEnabled) {
      assessmentType = 'credit';
      typeReason = 'grading_credit_enabled_only';
    } else if (examEnabled && creditEnabled) {
      if (examWeight > creditWeight) {
        assessmentType = 'exam';
        typeReason = 'grading_weights_exam_gt_credit';
      } else if (creditWeight > examWeight) {
        assessmentType = 'credit';
        typeReason = 'grading_weights_credit_gt_exam';
      } else if (!isRequired || looksLikePractice) {
        assessmentType = 'credit';
        typeReason = !isRequired ? 'optional_subject_bias_credit' : 'practice_subject_bias_credit';
      } else {
        assessmentType = 'exam';
        typeReason = 'required_subject_bias_exam';
      }
    } else if (!isRequired || looksLikePractice) {
      assessmentType = 'credit';
      typeReason = !isRequired ? 'optional_subject_fallback_credit' : 'practice_subject_fallback_credit';
    }

    const isDifferentiatedCredit = assessmentType === 'credit' && creditWeight > 0;
    const splitByGroups = !isGeneral && groupCount > 1;
    const groupNumbers = splitByGroups ? Array.from({ length: groupCount }, (_, idx) => idx + 1) : [null];
    const baseMarks = [];
    if (assessmentType === 'exam') baseMarks.push('EX');
    if (assessmentType === 'credit') baseMarks.push('CR');
    if (isDifferentiatedCredit) baseMarks.push('DIF');
    if (!isRequired) baseMarks.push('OPT');

    const complexityBase = assessmentType === 'exam' ? 3 : (isDifferentiatedCredit ? 2 : 1);
    const complexity = complexityBase + (splitByGroups ? 1 : 0) + (groupCountRaw >= 3 ? 1 : 0);
    const perGroupQueue = groupNumbers.map((groupNumber) => {
      const marks = [...baseMarks];
      if (groupNumber) marks.push(`G${groupNumber}`);
      return {
        subject_id: subjectId,
        subject_name: subject.name,
        group_number: groupNumber,
        group_label: groupNumber ? `Група ${groupNumber}` : (groupCountRaw > 1 ? `Всі групи (${groupCountRaw})` : 'Всі'),
        type: assessmentType,
        complexity,
        marks,
        is_required: isRequired,
        is_general: isGeneral,
        group_count: groupCountRaw,
        classification_reason: typeReason,
      };
    });

    sourceRows.push({
      subject_id: subjectId,
      subject_name: subject.name,
      group_count: groupCountRaw,
      scope_label: splitByGroups ? `Окремо по групах (${groupCountRaw})` : (groupCountRaw > 1 ? `Спільно (${groupCountRaw} групи)` : 'Одна група'),
      assessment_type: assessmentType,
      assessment_label: assessmentType === 'exam' ? 'Екзамен' : (isDifferentiatedCredit ? 'Диф. залік' : 'Залік'),
      marks: baseMarks,
      events_count: perGroupQueue.length,
      complexity,
      reason_key: typeReason,
      reason_text:
        typeReason === 'grading_exam_enabled_only' ? 'Grading: увімкнено лише exam' :
        typeReason === 'grading_credit_enabled_only' ? 'Grading: увімкнено лише credit' :
        typeReason === 'grading_weights_exam_gt_credit' ? 'Grading: вага exam > credit' :
        typeReason === 'grading_weights_credit_gt_exam' ? 'Grading: вага credit > exam' :
        typeReason === 'optional_subject_bias_credit' ? 'Евристика: необовʼязковий предмет → залік' :
        typeReason === 'practice_subject_bias_credit' ? 'Евристика: практичний/семінарний предмет → залік' :
        typeReason === 'required_subject_bias_exam' ? 'Евристика: обовʼязковий предмет → екзамен' :
        typeReason === 'optional_subject_fallback_credit' ? 'Fallback: необовʼязковий предмет → залік' :
        typeReason === 'practice_subject_fallback_credit' ? 'Fallback: практичний предмет → залік' :
        'Fallback: обовʼязковий предмет → екзамен',
    });
    queue.push(...perGroupQueue);
  });
  return { sourceRows, queue };
};

const buildSessionQueueWithStrategy = (queue, strategy, seed = 1) => {
  const sorted = [...(queue || [])];
  sorted.sort((a, b) => {
    if (a.type !== b.type) {
      if (strategy === 'credits_first') return a.type === 'credit' ? -1 : 1;
      if (strategy === 'exams_first') return a.type === 'exam' ? -1 : 1;
      if (a.complexity !== b.complexity) return b.complexity - a.complexity;
      return String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk');
    }
    if (a.complexity !== b.complexity) return b.complexity - a.complexity;
    const subjectCompare = String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk');
    if (subjectCompare !== 0) return subjectCompare;
    return Number(a.group_number || 0) - Number(b.group_number || 0);
  });
  if (strategy !== 'balanced') return sorted;

  const exams = sorted.filter((row) => row.type === 'exam');
  const credits = sorted.filter((row) => row.type === 'credit');
  const randomizedExams = shuffleArrayDeterministic(exams, seed + 11);
  const randomizedCredits = shuffleArrayDeterministic(credits, seed + 29);
  const examChunks = safeArrayChunk(randomizedExams, 2);
  const creditChunks = safeArrayChunk(randomizedCredits, 2);
  const merged = [];
  const maxLen = Math.max(examChunks.length, creditChunks.length);
  for (let i = 0; i < maxLen; i += 1) {
    if (examChunks[i]) merged.push(...examChunks[i]);
    if (creditChunks[i]) merged.push(...creditChunks[i]);
  }
  return merged;
};

const buildSessionDayBuckets = ({
  startDate,
  sessionDays,
  maxEventsPerDay,
  includeWeekends,
  respectStudyDays,
  activeStudyDayNames = [],
  explicitDates = [],
}) => {
  const buckets = [];
  const normalizedMax = Math.max(1, Number(maxEventsPerDay || 1));
  const activeStudyDaySet = new Set((activeStudyDayNames || []).map((day) => String(day)));
  const normalizedExplicitDates = Array.from(new Set((explicitDates || [])
    .map((date) => (isValidDateString(date) ? String(date) : null))
    .filter(Boolean)))
    .sort();
  if (normalizedExplicitDates.length) {
    normalizedExplicitDates.forEach((cursor) => {
      const dayName = getDayNameFromDate(cursor);
      const isWeekend = dayName === 'Saturday' || dayName === 'Sunday';
      if (!includeWeekends && isWeekend) return;
      if (respectStudyDays && activeStudyDaySet.size && !activeStudyDaySet.has(dayName)) return;
      buckets.push({
        date: cursor,
        day_name: dayName,
        day_short: getStudyDayShortLabel(dayName),
        items: [],
        capacity: normalizedMax,
        is_weekend: isWeekend,
        is_reserved: false,
        capacity_note: null,
      });
    });
    return buckets;
  }
  let cursor = isValidDateString(startDate) ? startDate : toIsoDateOnly(new Date());
  let attempts = 0;
  while (buckets.length < sessionDays && attempts < sessionDays * 10) {
    attempts += 1;
    const dayName = getDayNameFromDate(cursor);
    const isWeekend = dayName === 'Saturday' || dayName === 'Sunday';
    if (!includeWeekends && isWeekend) {
      cursor = addDaysIso(cursor, 1);
      continue;
    }
    if (respectStudyDays && activeStudyDaySet.size && !activeStudyDaySet.has(dayName)) {
      cursor = addDaysIso(cursor, 1);
      continue;
    }
    buckets.push({
      date: cursor,
      day_name: dayName,
      day_short: getStudyDayShortLabel(dayName),
      items: [],
      capacity: normalizedMax,
      is_weekend: isWeekend,
      is_reserved: false,
      capacity_note: null,
    });
    cursor = addDaysIso(cursor, 1);
  }
  return buckets;
};

const buildSessionDatesFromWeekNumbers = ({
  semester,
  weekNumbers = [],
  includeWeekends,
  respectStudyDays,
  activeStudyDayNames = [],
}) => {
  if (!semester || !semester.start_date || !isValidDateString(semester.start_date)) return [];
  const activeStudyDaySet = new Set((activeStudyDayNames || []).map((day) => String(day)));
  const dayOrder = includeWeekends ? fullWeekDays : daysOfWeek;
  const dates = [];
  (weekNumbers || []).forEach((weekNumber) => {
    (dayOrder || []).forEach((dayName) => {
      if (respectStudyDays && activeStudyDaySet.size && !activeStudyDaySet.has(dayName)) return;
      const date = getDateForWeekDay(weekNumber, dayName, semester.start_date);
      if (date && isValidDateString(date)) {
        dates.push(date);
      }
    });
  });
  return Array.from(new Set(dates)).sort();
};

const getSemesterWeekNumberForDate = (dateStr, semester) => {
  if (!dateStr || !semester || !semester.start_date) return null;
  const info = getWeekDayForDate(dateStr, semester.start_date);
  return info && Number.isFinite(Number(info.weekNumber)) ? Number(info.weekNumber) : null;
};

const buildSessionSlotBoard = ({
  dayBuckets = [],
  semester,
  scheduleRows = [],
  teacherMapBySubject = new Map(),
}) => {
  const busyMap = new Map();
  (scheduleRows || []).forEach((row) => {
    const week = Number(row.week_number);
    const classNum = Number(row.class_number);
    const dayName = String(row.day_of_week || '');
    if (!week || !classNum || !dayName) return;
    const key = `${week}|${dayName}|${classNum}`;
    if (!busyMap.has(key)) busyMap.set(key, []);
    const subjectId = Number(row.subject_id || 0);
    const groupNumber = Number(row.group_number || 0);
    const teachers = resolveSessionTeachersForGroup(
      teacherMapBySubject,
      subjectId,
      Number.isFinite(groupNumber) && groupNumber > 0 ? groupNumber : null
    );
    busyMap.get(key).push({
      subject_id: Number.isFinite(subjectId) && subjectId > 0 ? subjectId : null,
      subject_name: row.subject_name || 'Пара',
      lesson_type: row.lesson_type || '',
      group_number: row.group_number,
      teacher_ids: teachers.map((teacher) => Number(teacher.id)).filter((id) => Number.isFinite(id) && id > 0),
      teacher_names: teachers.map((teacher) => String(teacher.name || '')).filter(Boolean),
    });
  });

  return (dayBuckets || []).map((bucket) => {
    const weekNumber = getSemesterWeekNumberForDate(bucket.date, semester);
    const slotRows = [1, 2, 3, 4, 5, 6, 7].map((classNum) => {
      const key = `${weekNumber || 0}|${bucket.day_name || ''}|${classNum}`;
      const busy = weekNumber ? (busyMap.get(key) || []) : [];
      const slot = bellSchedule[classNum] || null;
      return {
        class_number: classNum,
        time_label: slot ? `${slot.start}-${slot.end}` : `#${classNum}`,
        is_busy: !!busy.length,
        is_free: !busy.length,
        busy,
      };
    });
    return {
      date: bucket.date,
      day_name: bucket.day_name,
      day_short: bucket.day_short,
      week_number: weekNumber,
      slots: slotRows,
      free_count: slotRows.filter((s) => s.is_free).length,
      busy_count: slotRows.filter((s) => s.is_busy).length,
    };
  });
};

const normalizeSessionPublishAction = (value) => {
  const raw = String(value || '').trim().toLowerCase();
  if (raw === 'check' || raw === 'check_conflicts') return 'check_conflicts';
  return 'publish';
};

const getSessionSubjectTeacherMap = async (subjectIds = []) => {
  const safeIds = Array.from(new Set((subjectIds || [])
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value) && value > 0)));
  if (!safeIds.length) return new Map();
  const rows = await db.all(
    `
      SELECT
        ts.subject_id,
        ts.group_number,
        ts.user_id,
        COALESCE(NULLIF(TRIM(u.full_name), ''), ('ID ' || ts.user_id::TEXT)) AS teacher_name
      FROM teacher_subjects ts
      LEFT JOIN users u ON u.id = ts.user_id
      WHERE ts.subject_id = ANY(?)
    `,
    [safeIds]
  );
  const result = new Map();
  (rows || []).forEach((row) => {
    const subjectId = Number(row.subject_id);
    const teacherId = Number(row.user_id);
    if (!Number.isFinite(subjectId) || subjectId < 1 || !Number.isFinite(teacherId) || teacherId < 1) return;
    if (!result.has(subjectId)) {
      result.set(subjectId, { all: new Map(), byGroup: new Map() });
    }
    const subjectMap = result.get(subjectId);
    const teacherName = String(row.teacher_name || `ID ${teacherId}`);
    if (row.group_number === null || typeof row.group_number === 'undefined') {
      subjectMap.all.set(teacherId, teacherName);
      return;
    }
    const groupNumber = Number(row.group_number);
    if (!Number.isFinite(groupNumber) || groupNumber < 1) return;
    if (!subjectMap.byGroup.has(groupNumber)) {
      subjectMap.byGroup.set(groupNumber, new Map());
    }
    subjectMap.byGroup.get(groupNumber).set(teacherId, teacherName);
  });
  return result;
};

const resolveSessionTeachersForGroup = (teacherMapBySubject, subjectId, groupNumber) => {
  const subjectMap = teacherMapBySubject && teacherMapBySubject.get(Number(subjectId));
  if (!subjectMap) return [];
  const collected = new Map();
  (subjectMap.all || new Map()).forEach((name, teacherId) => {
    collected.set(Number(teacherId), String(name || `ID ${teacherId}`));
  });
  const safeGroup = Number(groupNumber);
  if (Number.isFinite(safeGroup) && safeGroup > 0 && subjectMap.byGroup && subjectMap.byGroup.has(safeGroup)) {
    subjectMap.byGroup.get(safeGroup).forEach((name, teacherId) => {
      collected.set(Number(teacherId), String(name || `ID ${teacherId}`));
    });
  }
  return Array.from(collected.entries())
    .map(([teacherId, teacherName]) => ({
      id: Number(teacherId),
      name: String(teacherName || `ID ${teacherId}`),
    }))
    .filter((teacher) => Number.isFinite(teacher.id) && teacher.id > 0)
    .sort((a, b) => a.name.localeCompare(b.name, 'uk'));
};

const serializeSessionTeacherMap = (teacherMapBySubject) => {
  const payload = {};
  if (!teacherMapBySubject || typeof teacherMapBySubject.forEach !== 'function') return payload;
  teacherMapBySubject.forEach((subjectMap, subjectIdRaw) => {
    const subjectId = Number(subjectIdRaw);
    if (!Number.isFinite(subjectId) || subjectId < 1) return;
    const all = Array.from((subjectMap && subjectMap.all) ? subjectMap.all.keys() : [])
      .map((teacherId) => Number(teacherId))
      .filter((teacherId) => Number.isFinite(teacherId) && teacherId > 0);
    const byGroup = {};
    if (subjectMap && subjectMap.byGroup && typeof subjectMap.byGroup.forEach === 'function') {
      subjectMap.byGroup.forEach((groupMap, groupNumberRaw) => {
        const groupNumber = Number(groupNumberRaw);
        if (!Number.isFinite(groupNumber) || groupNumber < 1) return;
        const ids = Array.from(groupMap.keys())
          .map((teacherId) => Number(teacherId))
          .filter((teacherId) => Number.isFinite(teacherId) && teacherId > 0);
        if (ids.length) {
          byGroup[String(groupNumber)] = ids;
        }
      });
    }
    payload[String(subjectId)] = {
      all,
      by_group: byGroup,
    };
  });
  return payload;
};

const buildSessionTeacherFilterOptions = (teacherMapBySubject) => {
  const optionsMap = new Map();
  if (!teacherMapBySubject || typeof teacherMapBySubject.forEach !== 'function') return [];
  teacherMapBySubject.forEach((subjectMap) => {
    (subjectMap && subjectMap.all ? subjectMap.all : new Map()).forEach((name, teacherIdRaw) => {
      const teacherId = Number(teacherIdRaw);
      if (!Number.isFinite(teacherId) || teacherId < 1) return;
      optionsMap.set(teacherId, String(name || `ID ${teacherId}`));
    });
    if (subjectMap && subjectMap.byGroup && typeof subjectMap.byGroup.forEach === 'function') {
      subjectMap.byGroup.forEach((groupMap) => {
        groupMap.forEach((name, teacherIdRaw) => {
          const teacherId = Number(teacherIdRaw);
          if (!Number.isFinite(teacherId) || teacherId < 1) return;
          optionsMap.set(teacherId, String(name || `ID ${teacherId}`));
        });
      });
    }
  });
  return Array.from(optionsMap.entries())
    .map(([id, name]) => ({ id, name }))
    .sort((a, b) => String(a.name || '').localeCompare(String(b.name || ''), 'uk'));
};

const buildSessionExpandedAssignments = (assessments = [], subjectById = new Map()) => {
  const rows = [];
  (assessments || []).forEach((assessment) => {
    const subjectId = Number(assessment.subject_id);
    const subject = subjectById.get(subjectId);
    if (!subject) return;
    const groupCount = Math.max(1, Number(subject.group_count || 1));
    const oneGroup = Number(assessment.group_number || 0);
    const targetGroups = Number.isFinite(oneGroup) && oneGroup > 0
      ? (oneGroup <= groupCount ? [oneGroup] : [])
      : Array.from({ length: groupCount }, (_value, index) => index + 1);
    const classNumber = Number(assessment.class_number || 0);
    const date = toDateOnly(assessment.date);
    const dayName = normalizeWeekdayName(
      String(assessment.day_name || getDayNameFromDate(date) || '').trim()
    );
    if (!targetGroups.length || !dayName || !isValidDateString(date) || classNumber < 1 || classNumber > 7) {
      return;
    }
    targetGroups.forEach((groupNumber) => {
      rows.push({
        subject_id: subjectId,
        subject_name: subject.name || assessment.subject_name || '',
        group_number: Number(groupNumber),
        date,
        day_name: dayName,
        class_number: classNumber,
        type: assessment.type === 'credit'
          ? 'credit'
          : (assessment.type === 'consultation' ? 'consultation' : 'exam'),
        note: String(assessment.note || ''),
      });
    });
  });
  return rows.sort((a, b) => {
    const byDate = String(a.date || '').localeCompare(String(b.date || ''));
    if (byDate !== 0) return byDate;
    const byClass = Number(a.class_number || 0) - Number(b.class_number || 0);
    if (byClass !== 0) return byClass;
    const bySubject = String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk');
    if (bySubject !== 0) return bySubject;
    return Number(a.group_number || 0) - Number(b.group_number || 0);
  });
};

const getSessionTeacherBusyMap = async (teacherIds = []) => {
  const safeTeacherIds = Array.from(new Set((teacherIds || [])
    .map((value) => Number(value))
    .filter((value) => Number.isFinite(value) && value > 0)));
  const busyMap = new Map();
  if (!safeTeacherIds.length) return busyMap;

  const scheduleRows = await db.all(
    `
      SELECT DISTINCT
        ts.user_id AS teacher_id,
        COALESCE(NULLIF(TRIM(u.full_name), ''), ('ID ' || ts.user_id::TEXT)) AS teacher_name,
        se.id AS source_id,
        se.course_id,
        COALESCE(c.name, ('Курс ' || se.course_id::TEXT)) AS course_name,
        se.subject_id,
        s.name AS subject_name,
        se.group_number,
        se.day_of_week,
        se.class_number,
        se.week_number,
        sem.start_date
      FROM schedule_entries se
      JOIN subjects s ON s.id = se.subject_id
      JOIN semesters sem ON sem.id = se.semester_id
      JOIN teacher_subjects ts ON ts.subject_id = se.subject_id
        AND (ts.group_number IS NULL OR ts.group_number = se.group_number)
      LEFT JOIN users u ON u.id = ts.user_id
      LEFT JOIN courses c ON c.id = se.course_id
      WHERE ts.user_id = ANY(?)
        AND se.class_number BETWEEN 1 AND 7
    `,
    [safeTeacherIds]
  );
  (scheduleRows || []).forEach((row) => {
    const teacherId = Number(row.teacher_id);
    const classNumber = Number(row.class_number);
    const weekNumber = Number(row.week_number);
    const dayName = normalizeWeekdayName(row.day_of_week);
    const startDate = row.start_date ? String(row.start_date) : null;
    if (
      !Number.isFinite(teacherId)
      || teacherId < 1
      || !Number.isFinite(classNumber)
      || classNumber < 1
      || classNumber > 7
      || !Number.isFinite(weekNumber)
      || weekNumber < 1
      || !dayName
      || !startDate
    ) {
      return;
    }
    const classDate = getDateForWeekDay(weekNumber, dayName, startDate);
    if (!classDate || !isValidDateString(classDate)) return;
    const slotKey = `${teacherId}|${classDate}|${classNumber}`;
    if (!busyMap.has(slotKey)) busyMap.set(slotKey, []);
    busyMap.get(slotKey).push({
      source_kind: 'schedule',
      source_ref: `schedule:${row.source_id}`,
      teacher_id: teacherId,
      teacher_name: String(row.teacher_name || `ID ${teacherId}`),
      date: classDate,
      class_number: classNumber,
      course_id: Number(row.course_id || 0) || null,
      course_name: String(row.course_name || ''),
      subject_id: Number(row.subject_id || 0) || null,
      subject_name: String(row.subject_name || ''),
      group_number: Number(row.group_number || 0) || null,
    });
  });

  const homeworkRows = await db.all(
    `
      SELECT DISTINCT
        ts.user_id AS teacher_id,
        COALESCE(NULLIF(TRIM(u.full_name), ''), ('ID ' || ts.user_id::TEXT)) AS teacher_name,
        h.id AS source_id,
        h.course_id,
        COALESCE(c.name, ('Курс ' || h.course_id::TEXT)) AS course_name,
        h.subject_id,
        COALESCE(NULLIF(TRIM(s.name), ''), NULLIF(TRIM(h.subject), ''), 'Подія') AS subject_name,
        h.group_number,
        h.class_number,
        h.class_date
      FROM homework h
      JOIN teacher_subjects ts ON ts.subject_id = h.subject_id
        AND (ts.group_number IS NULL OR ts.group_number = h.group_number)
      LEFT JOIN users u ON u.id = ts.user_id
      LEFT JOIN subjects s ON s.id = h.subject_id
      LEFT JOIN courses c ON c.id = h.course_id
      WHERE ts.user_id = ANY(?)
        AND h.class_date IS NOT NULL
        AND h.class_number BETWEEN 1 AND 7
        AND COALESCE(h.status, 'published') IN ('draft', 'scheduled', 'published')
        AND COALESCE(h.is_teacher_homework, 0) = 1
        AND (
          COALESCE(h.is_control, 0) = 1
          OR LOWER(TRIM(COALESCE(h.description, ''))) LIKE '[сесія]%'
        )
    `,
    [safeTeacherIds]
  );
  (homeworkRows || []).forEach((row) => {
    const teacherId = Number(row.teacher_id);
    const classNumber = Number(row.class_number);
    const classDate = toDateOnly(row.class_date);
    if (
      !Number.isFinite(teacherId)
      || teacherId < 1
      || !Number.isFinite(classNumber)
      || classNumber < 1
      || classNumber > 7
      || !isValidDateString(classDate)
    ) {
      return;
    }
    const slotKey = `${teacherId}|${classDate}|${classNumber}`;
    if (!busyMap.has(slotKey)) busyMap.set(slotKey, []);
    busyMap.get(slotKey).push({
      source_kind: 'homework',
      source_ref: `homework:${row.source_id}`,
      teacher_id: teacherId,
      teacher_name: String(row.teacher_name || `ID ${teacherId}`),
      date: classDate,
      class_number: classNumber,
      course_id: Number(row.course_id || 0) || null,
      course_name: String(row.course_name || ''),
      subject_id: Number(row.subject_id || 0) || null,
      subject_name: String(row.subject_name || ''),
      group_number: Number(row.group_number || 0) || null,
    });
  });

  return busyMap;
};

const buildSessionTeacherConflictReport = async ({
  expandedAssignments = [],
  selectedCourseId,
}) => {
  const subjectIds = Array.from(new Set((expandedAssignments || [])
    .map((row) => Number(row.subject_id))
    .filter((value) => Number.isFinite(value) && value > 0)));
  const teacherMapBySubject = await getSessionSubjectTeacherMap(subjectIds);
  const enrichedRows = [];
  const unresolvedRows = [];
  (expandedAssignments || []).forEach((row) => {
    const teachers = resolveSessionTeachersForGroup(teacherMapBySubject, row.subject_id, row.group_number);
    if (!teachers.length) {
      unresolvedRows.push(row);
      return;
    }
    enrichedRows.push({
      ...row,
      teachers,
    });
  });
  const teacherIds = Array.from(new Set(enrichedRows.flatMap((row) => row.teachers.map((teacher) => teacher.id))));
  const busyMap = await getSessionTeacherBusyMap(teacherIds);
  const draftMap = new Map();
  const conflicts = [];
  const conflictDedup = new Set();

  const pushConflict = (payload) => {
    const key = [
      payload.type,
      Number(payload.teacher_id || 0),
      String(payload.date || ''),
      Number(payload.class_number || 0),
      String(payload.source_ref || ''),
      String(payload.other_ref || ''),
    ].join('|');
    if (conflictDedup.has(key)) return;
    conflictDedup.add(key);
    conflicts.push(payload);
  };

  enrichedRows.forEach((row) => {
    row.teachers.forEach((teacher) => {
      const slotKey = `${teacher.id}|${row.date}|${row.class_number}`;
      if (!draftMap.has(slotKey)) draftMap.set(slotKey, []);
      const sameDraftSlotRows = draftMap.get(slotKey);
      sameDraftSlotRows.forEach((otherRow) => {
        const sameTarget = Number(otherRow.subject_id || 0) === Number(row.subject_id || 0)
          && Number(otherRow.group_number || 0) === Number(row.group_number || 0)
          && String(otherRow.type || '') === String(row.type || '');
        if (sameTarget) return;
        pushConflict({
          type: 'draft',
          teacher_id: teacher.id,
          teacher_name: teacher.name,
          date: row.date,
          class_number: row.class_number,
          source_ref: `${row.subject_id}|${row.group_number}`,
          other_ref: `${otherRow.subject_id}|${otherRow.group_number}`,
          details: {
            current: row,
            other: otherRow,
          },
        });
      });
      sameDraftSlotRows.push(row);

      const busyRows = busyMap.get(slotKey) || [];
      busyRows.forEach((busy) => {
        const sameTarget = Number(busy.course_id || 0) === Number(selectedCourseId || 0)
          && Number(busy.subject_id || 0) === Number(row.subject_id || 0)
          && Number(busy.group_number || 0) === Number(row.group_number || 0);
        if (sameTarget) return;
        pushConflict({
          type: 'occupied',
          teacher_id: teacher.id,
          teacher_name: teacher.name,
          date: row.date,
          class_number: row.class_number,
          source_ref: String(busy.source_ref || ''),
          other_ref: `${row.subject_id}|${row.group_number}`,
          details: {
            current: row,
            busy,
          },
        });
      });
    });
  });

  conflicts.sort((a, b) => {
    const byDate = String(a.date || '').localeCompare(String(b.date || ''));
    if (byDate !== 0) return byDate;
    const byClass = Number(a.class_number || 0) - Number(b.class_number || 0);
    if (byClass !== 0) return byClass;
    return String(a.teacher_name || '').localeCompare(String(b.teacher_name || ''), 'uk');
  });

  return {
    conflicts,
    unresolvedRows,
    checkedRows: enrichedRows.length,
  };
};

const formatSessionTeacherConflictMessage = (report) => {
  if (!report) return 'Невідома помилка перевірки конфліктів.';
  const conflicts = Array.isArray(report.conflicts) ? report.conflicts : [];
  const unresolvedRows = Array.isArray(report.unresolvedRows) ? report.unresolvedRows : [];
  if (!conflicts.length && !unresolvedRows.length) {
    return `Конфліктів викладачів не знайдено (${Number(report.checkedRows || 0)} перевірених подій).`;
  }
  const samples = conflicts.slice(0, 4).map((row) => {
    if (row.type === 'draft') {
      return `${row.teacher_name}: ${row.date}, пара ${row.class_number} (дубль у плані)`;
    }
    const busy = row.details && row.details.busy ? row.details.busy : null;
    const courseLabel = busy && busy.course_name ? busy.course_name : (busy && busy.course_id ? `Курс ${busy.course_id}` : 'інший курс');
    const subjectLabel = busy && busy.subject_name ? busy.subject_name : 'інша пара';
    const groupLabel = busy && Number.isFinite(Number(busy.group_number)) && Number(busy.group_number) > 0
      ? `, група ${busy.group_number}`
      : '';
    return `${row.teacher_name}: ${row.date}, пара ${row.class_number} (${courseLabel} · ${subjectLabel}${groupLabel})`;
  });
  const parts = [];
  if (conflicts.length) {
    parts.push(`Знайдено конфліктів: ${conflicts.length}.`);
  }
  if (samples.length) {
    parts.push(`Приклади: ${samples.join('; ')}.`);
  }
  if (unresolvedRows.length) {
    parts.push(`Без привʼязаного викладача: ${unresolvedRows.length} подій.`);
  }
  return parts.join(' ').trim();
};

const buildSessionConflictSlotMap = (report) => {
  const slotMap = {};
  const conflicts = Array.isArray(report && report.conflicts) ? report.conflicts : [];
  conflicts.forEach((conflict) => {
    const date = String(conflict && conflict.date ? conflict.date : '');
    const classNumber = Number(conflict && conflict.class_number ? conflict.class_number : 0);
    if (!date || !Number.isFinite(classNumber) || classNumber < 1) return;
    const key = `${date}|${classNumber}`;
    if (!slotMap[key]) {
      slotMap[key] = {
        date,
        class_number: classNumber,
        conflicts_total: 0,
        draft_conflicts: 0,
        occupied_conflicts: 0,
        reasons: [],
      };
    }
    const slotRow = slotMap[key];
    slotRow.conflicts_total += 1;
    if (conflict.type === 'draft') {
      slotRow.draft_conflicts += 1;
      slotRow.reasons.push(`${conflict.teacher_name || 'Викладач'}: дубль у ручному плані`);
    } else {
      slotRow.occupied_conflicts += 1;
      const busy = conflict.details && conflict.details.busy ? conflict.details.busy : null;
      const subjectLabel = busy && busy.subject_name ? busy.subject_name : 'інша подія';
      const courseLabel = busy && busy.course_name ? busy.course_name : 'інший курс';
      slotRow.reasons.push(`${conflict.teacher_name || 'Викладач'}: зайнятий (${courseLabel} · ${subjectLabel})`);
    }
  });
  Object.values(slotMap).forEach((slotRow) => {
    const uniqueReasons = Array.from(new Set((slotRow.reasons || []).map((text) => String(text).trim()).filter(Boolean)));
    slotRow.reasons = uniqueReasons.slice(0, 4);
    slotRow.reason_text = uniqueReasons.slice(0, 2).join('; ');
  });
  return slotMap;
};

const sessionEventTitleLabel = (event) => {
  if (!event) return '';
  if (event.kind === 'consultation') return 'Консультація';
  if (event.kind === 'reserve') return 'Резерв / перенос';
  if (event.kind === 'retake') return 'Вікно перескладань';
  return event.type === 'exam' ? 'Екзамен' : 'Залік';
};

const buildSessionGeneratorPreview = ({
  subjects = [],
  gradingBySubject = {},
  startDate,
  sessionDays,
  explicitDates = [],
  maxEventsPerDay,
  reserveEvery,
  examGapDays,
  retakeGapDays,
  retakeWindowDays,
  includeConsultations,
  includeWeekends,
  respectStudyDays,
  activeStudyDayNames = [],
  dayGroupingMode = 'none',
  examSequence = 'consult_exam',
  creditSequence = 'credit_only',
  strategy,
  seed,
}) => {
  const warnings = [];
  const notes = [];
  const assumptions = [
    'Тип контролю визначається за grading settings (якщо є) + fallback правилами класифікації.',
    'Опублікувати можна як авто-план, так і ручний план із вибраних слотів; заліки синхронізуються в журнал.',
  ];
  if (!subjects.length) {
    return {
      dayBuckets: [],
      timelineItems: [],
      sourceRows: [],
      warnings: ['Немає видимих предметів для вибраного курсу.'],
      notes,
      assumptions,
      stats: {
        subjects_count: 0,
        assessments_total: 0,
        exams_total: 0,
        credits_total: 0,
        consultations_total: 0,
        reserve_days_total: 0,
        retake_windows_total: 0,
        used_slots: 0,
        capacity_total: 0,
        free_slots: 0,
        free_days: 0,
        overloaded_days: 0,
      },
    };
  }

  const { sourceRows, queue } = buildSessionAssessmentPlan({ subjects, gradingBySubject });
  const sortedQueue = buildSessionQueueWithStrategy(queue, strategy, seed);
  const dayBuckets = buildSessionDayBuckets({
    startDate,
    sessionDays,
    maxEventsPerDay,
    includeWeekends,
    respectStudyDays,
    activeStudyDayNames,
    explicitDates,
  });

  if (!dayBuckets.length) {
    warnings.push('Не вдалося побудувати календарні дні для сесії (перевірте дату старту та фільтр днів).');
  }

  const lastExamByScope = {};
  const daySubjectSetByDate = new Map();
  const dayActivityTypeSetByDate = new Map();
  const getDaySet = (map, date) => {
    if (!map.has(date)) map.set(date, new Set());
    return map.get(date);
  };
  const eventActivityKey = (event) => {
    if (!event) return '';
    if (event.kind === 'consultation') return 'consultation';
    if (event.kind === 'reserve') return 'reserve';
    if (event.kind === 'retake') return 'retake';
    if (event.kind === 'assessment') return String(event.type || 'assessment');
    return String(event.kind || event.type || '');
  };
  const canUseBucketByGrouping = (bucket, eventLike) => {
    if (!bucket) return false;
    if (dayGroupingMode === 'subject_per_day' && eventLike && eventLike.subject_name) {
      const subjectSet = getDaySet(daySubjectSetByDate, bucket.date);
      if (subjectSet.size && !subjectSet.has(String(eventLike.subject_name))) return false;
    }
    if (dayGroupingMode === 'activity_per_day') {
      const activitySet = getDaySet(dayActivityTypeSetByDate, bucket.date);
      const key = eventActivityKey(eventLike);
      if (activitySet.size && key && !activitySet.has(key)) return false;
    }
    return true;
  };
  const addEventToBucket = (bucket, event) => {
    if (!bucket) return false;
    bucket.items.push(event);
    if (event && event.subject_name) {
      getDaySet(daySubjectSetByDate, bucket.date).add(String(event.subject_name));
    }
    const activityKey = eventActivityKey(event);
    if (activityKey) {
      getDaySet(dayActivityTypeSetByDate, bucket.date).add(activityKey);
    }
    return true;
  };

  const chooseBucketForAssessment = (assessment) => {
    const scopeKey = assessment.group_number ? `G${assessment.group_number}` : 'ALL';
    const candidateBuckets = dayBuckets.filter((bucket) =>
      bucket.items.length < bucket.capacity && canUseBucketByGrouping(bucket, { kind: 'assessment', type: assessment.type, subject_name: assessment.subject_name })
    );
    const relaxedBuckets = dayBuckets.filter((bucket) => bucket.items.length < bucket.capacity);
    const effectiveBuckets = candidateBuckets.length ? candidateBuckets : relaxedBuckets;
    let fallbackBucket = effectiveBuckets[0] || null;
    for (const bucket of effectiveBuckets) {
      if (assessment.type !== 'exam') return bucket;
      const lastDate = lastExamByScope[scopeKey] || (scopeKey !== 'ALL' ? lastExamByScope.ALL : null) || null;
      if (!lastDate) return bucket;
      const diff = diffDaysIso(bucket.date, lastDate);
      if (diff === null) return bucket;
      if (diff > Math.max(0, examGapDays)) {
        return bucket;
      }
      fallbackBucket = fallbackBucket || bucket;
    }
    return fallbackBucket;
  };

  let scheduledAssessments = 0;
  let examCount = 0;
  let creditCount = 0;
  let consultCount = 0;
  let reserveCount = 0;
  let overflowCount = 0;
  const placeRelativeEvent = ({
    sourceDate,
    direction,
    event,
    preferSameSubjectGap = true,
  }) => {
    const targetIndex = dayBuckets.findIndex((bucket) => bucket.date === sourceDate);
    if (targetIndex < 0) return false;
    const start = direction < 0 ? targetIndex - 1 : targetIndex + 1;
    const end = direction < 0 ? -1 : dayBuckets.length;
    for (let idx = start; direction < 0 ? idx > end : idx < end; idx += direction) {
      const bucket = dayBuckets[idx];
      if (!bucket || bucket.items.length >= bucket.capacity) continue;
      if (!canUseBucketByGrouping(bucket, event)) continue;
      if (preferSameSubjectGap && event && event.subject_name) {
        const hasSameSubject = bucket.items.some((item) => item.subject_name && item.subject_name === event.subject_name);
        if (hasSameSubject) continue;
      }
      addEventToBucket(bucket, event);
      return true;
    }
    return false;
  };

  sortedQueue.forEach((assessment) => {
    const bucket = chooseBucketForAssessment(assessment);
    if (!bucket) {
      overflowCount += 1;
      warnings.push(`Не вистачило слотів для "${assessment.subject_name}" (${assessment.group_label}).`);
      return;
    }
    const isHeavy = assessment.type === 'exam' && assessment.complexity >= 4;
    const marks = [...assessment.marks];
    if (isHeavy) marks.push('CAP');
    const event = {
      kind: 'assessment',
      type: assessment.type,
      subject_id: assessment.subject_id,
      subject_name: assessment.subject_name,
      group_label: assessment.group_label,
      group_number: assessment.group_number,
      marks,
      complexity: assessment.complexity,
      title: sessionEventTitleLabel(assessment),
      note: assessment.is_required ? '' : 'Необовʼязковий предмет',
    };
    addEventToBucket(bucket, event);
    scheduledAssessments += 1;
    if (assessment.type === 'exam') {
      examCount += 1;
      const scopeKey = assessment.group_number ? `G${assessment.group_number}` : 'ALL';
      lastExamByScope[scopeKey] = bucket.date;
      if (!assessment.group_number) lastExamByScope.ALL = bucket.date;
      const needsConsult =
        examSequence === 'consult_exam' || examSequence === 'consult_exam_credit' || (includeConsultations && examSequence === 'exam_only');
      if (needsConsult) {
        const placedConsult = placeRelativeEvent({
          sourceDate: bucket.date,
          direction: -1,
          event: {
            kind: 'consultation',
            type: 'consultation',
            subject_name: assessment.subject_name,
            group_label: assessment.group_label,
            marks: ['CONS'],
            title: 'Консультація',
            note: `Перед "${assessment.subject_name}"`,
            complexity: 0,
          },
        });
        if (placedConsult) {
          consultCount += 1;
        } else {
          notes.push(`Не вдалося вставити консультацію перед "${assessment.subject_name}" (немає вільного дня/слота).`);
        }
      }
      if (examSequence === 'consult_exam_credit') {
        const placedCreditAfterExam = placeRelativeEvent({
          sourceDate: bucket.date,
          direction: 1,
          event: {
            kind: 'assessment',
            type: 'credit',
            subject_id: assessment.subject_id,
            subject_name: assessment.subject_name,
            group_label: assessment.group_label,
            group_number: assessment.group_number,
            marks: Array.from(new Set([...(assessment.marks || []).filter((m) => m !== 'EX'), 'CR'])),
            complexity: Math.max(0, Number(assessment.complexity || 0) - 1),
            title: 'Залік',
            note: 'Після екзамену',
          },
        });
        if (placedCreditAfterExam) {
          scheduledAssessments += 1;
          creditCount += 1;
        } else {
          notes.push(`Не вдалося вставити залік після екзамену для "${assessment.subject_name}".`);
        }
      }
    } else {
      creditCount += 1;
      if (creditSequence === 'consult_credit' || (includeConsultations && creditSequence === 'credit_only')) {
        const placedConsult = placeRelativeEvent({
          sourceDate: bucket.date,
          direction: -1,
          event: {
            kind: 'consultation',
            type: 'consultation',
            subject_name: assessment.subject_name,
            group_label: assessment.group_label,
            marks: ['CONS'],
            title: 'Консультація',
            note: `Перед заліком "${assessment.subject_name}"`,
            complexity: 0,
          },
        });
        if (placedConsult) {
          consultCount += 1;
        } else {
          notes.push(`Не вдалося вставити консультацію перед заліком "${assessment.subject_name}".`);
        }
      }
    }
  });

  if (Number(reserveEvery) > 0) {
    let assessmentsSeen = 0;
    dayBuckets.forEach((bucket) => {
      const assessmentsOnDay = bucket.items.filter((item) => item.kind === 'assessment').length;
      if (!assessmentsOnDay) return;
      assessmentsSeen += assessmentsOnDay;
      if (assessmentsSeen > 0 && assessmentsSeen % reserveEvery === 0) {
        bucket.is_reserved = true;
        bucket.capacity_note = 'Після цього дня бажано мати резерв/перенос';
        bucket.items.push({
          kind: 'reserve',
          type: 'reserve',
          marks: ['RES'],
          title: 'Резерв / перенос',
          note: 'Рекомендується закласти буфер після блоку контрольних',
          complexity: 0,
        });
        reserveCount += 1;
      }
    });
  }

  const lastAssessmentDate = [...dayBuckets]
    .reverse()
    .find((bucket) => bucket.items.some((item) => item.kind === 'assessment'))?.date || null;
  if (lastAssessmentDate) {
    const retakeStart = addDaysIso(lastAssessmentDate, Math.max(1, Number(retakeGapDays || 1)));
    const retakeEnd = addDaysIso(retakeStart, Math.max(0, Number(retakeWindowDays || 1) - 1));
    if (retakeStart) {
      const existing = dayBuckets.find((bucket) => bucket.date === retakeStart);
      const retakeEvent = {
        kind: 'retake',
        type: 'retake',
        marks: ['RET'],
        title: 'Вікно перескладань',
        note: retakeEnd && retakeEnd !== retakeStart ? `${retakeStart} → ${retakeEnd}` : retakeStart,
        complexity: 0,
      };
      if (existing) {
        existing.items.push(retakeEvent);
      } else {
        dayBuckets.push({
          date: retakeStart,
          day_name: getDayNameFromDate(retakeStart),
          day_short: getStudyDayShortLabel(getDayNameFromDate(retakeStart)),
          items: [retakeEvent],
          capacity: maxEventsPerDay,
          is_weekend: ['Saturday', 'Sunday'].includes(getDayNameFromDate(retakeStart)),
          is_reserved: false,
          capacity_note: null,
          is_extra_tail: true,
        });
      }
    }
  }

  dayBuckets.sort((a, b) => String(a.date).localeCompare(String(b.date)));
  dayBuckets.forEach((bucket) => {
    bucket.items.sort((a, b) => {
      const priority = { reserve: 9, retake: 8, consultation: 2, assessment: 1 };
      const pa = priority[a.kind] || 5;
      const pb = priority[b.kind] || 5;
      if (pa !== pb) return pa - pb;
      const typeOrder = { exam: 1, credit: 2 };
      const ta = typeOrder[a.type] || 9;
      const tb = typeOrder[b.type] || 9;
      if (ta !== tb) return ta - tb;
      return String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk');
    });
  });

  const capacityTotal = dayBuckets
    .filter((bucket) => !bucket.is_extra_tail)
    .reduce((sum, bucket) => sum + Number(bucket.capacity || 0), 0);
  const usedAssessmentSlots = dayBuckets
    .reduce((sum, bucket) => sum + bucket.items.filter((item) => item.kind === 'assessment').length, 0);
  const freeSlots = Math.max(0, capacityTotal - usedAssessmentSlots);
  const freeDays = dayBuckets.filter((bucket) => bucket.items.length === 0).length;
  const overloadedDays = dayBuckets.filter((bucket) =>
    bucket.items.filter((item) => item.kind === 'assessment').length >= Math.max(1, Number(bucket.capacity || 1))
  ).length;
  if (usedAssessmentSlots > capacityTotal) {
    warnings.push(`Потрібно більше слотів: оцінювань ${usedAssessmentSlots}, місткість ${capacityTotal}.`);
  }
  if (overloadedDays && usedAssessmentSlots) {
    notes.push(`Днів з повним навантаженням: ${overloadedDays}. Можна збільшити тривалість сесії або зменшити max подій/день.`);
  }
  if (overflowCount > 0) {
    warnings.push(`Частина подій не потрапила в календар (${overflowCount}).`);
  }
  if (respectStudyDays && !activeStudyDayNames.length) {
    notes.push('Увімкнено "лише навчальні дні", але активні дні курсу не знайдені — використано звичайний календарний фільтр.');
  }

  const timelineItems = [];
  dayBuckets.forEach((bucket) => {
    bucket.date_label = bucket.date;
    bucket.day_label = bucket.day_name ? `${bucket.day_short} · ${bucket.day_name}` : bucket.day_short;
    bucket.assessment_count = bucket.items.filter((item) => item.kind === 'assessment').length;
    timelineItems.push(...bucket.items.map((item) => ({
      ...item,
      date: bucket.date,
      day_name: bucket.day_name,
      day_short: bucket.day_short,
      date_label: bucket.date,
    })));
  });

  return {
    dayBuckets,
    timelineItems,
    sourceRows: sourceRows.sort((a, b) => {
      if (a.complexity !== b.complexity) return b.complexity - a.complexity;
      return String(a.subject_name || '').localeCompare(String(b.subject_name || ''), 'uk');
    }),
    warnings: Array.from(new Set(warnings)).slice(0, 8),
    notes,
    assumptions,
    stats: {
      subjects_count: sourceRows.length,
      assessments_total: scheduledAssessments,
      exams_total: examCount,
      credits_total: creditCount,
      consultations_total: consultCount,
      reserve_days_total: reserveCount,
      retake_windows_total: lastAssessmentDate ? 1 : 0,
      used_slots: usedAssessmentSlots,
      capacity_total: capacityTotal,
      free_slots: freeSlots,
      free_days: freeDays,
      overloaded_days: overloadedDays,
    },
  };
};

app.get('/admin/session-generator', requireScheduleGeneratorSectionAccess, async (req, res) => {
  try {
    await ensureDbReady();
  } catch (err) {
    return handleDbError(res, err, 'admin.sessionGenerator.init');
  }
  try {
    const query = req.query || {};
    const userId = Number(req.session && req.session.user ? req.session.user.id : 0);
    const requestedDraftId = parseSessionGeneratorInt(query.draft_id, null, 1, Number.MAX_SAFE_INTEGER);
    const draftActionRaw = String(query.draft_action || query.action || '').trim().toLowerCase();
    const draftAction = draftActionRaw === 'new' ? 'new' : draftActionRaw === 'clear' ? 'clear' : '';
    let draftEntries = Number.isFinite(userId) && userId > 0
      ? await listSessionGeneratorDraftRecords(userId)
      : [];
    let draftRecord = requestedDraftId
      ? ((draftEntries || []).find((entry) => Number(entry.id) === Number(requestedDraftId)) || null)
      : ((draftEntries || [])[0] || null);

    const seedLocation = normalizeGeneratorLocation(
      hasOwnQueryKey(query, 'location')
        ? query.location
        : (draftRecord && draftRecord.form ? draftRecord.form.location : 'kyiv')
    );

    const coursesByLocation = {
      kyiv: await getCoursesByLocation('kyiv'),
      munich: await getCoursesByLocation('munich'),
    };
    const activeLocation = seedLocation;
    const locationCourseIds = new Set((coursesByLocation[activeLocation] || []).map((c) => Number(c.id)));
    const preferredCourseIdRaw = hasOwnQueryKey(query, 'course_id')
      ? query.course_id
      : (draftRecord && draftRecord.form ? draftRecord.form.course_id : null);
    const preferredCourseId = parseSessionGeneratorInt(preferredCourseIdRaw, null, 1, Number.MAX_SAFE_INTEGER);
    let selectedCourseId = preferredCourseId && locationCourseIds.has(preferredCourseId)
      ? preferredCourseId
      : ((coursesByLocation[activeLocation] || [])[0] ? Number(coursesByLocation[activeLocation][0].id) : null);
    if (!selectedCourseId && preferredCourseId) {
      const crossLocationCourse = [...(coursesByLocation.kyiv || []), ...(coursesByLocation.munich || [])]
        .find((course) => Number(course.id) === Number(preferredCourseId));
      if (crossLocationCourse) {
        selectedCourseId = Number(crossLocationCourse.id);
      }
    }

    const semesters = selectedCourseId ? await getSemestersCached(selectedCourseId) : [];
    const requestedSemesterIdRaw = hasOwnQueryKey(query, 'semester_id')
      ? query.semester_id
      : (draftRecord && draftRecord.form ? draftRecord.form.semester_id : null);
    const requestedSemesterId = parseSessionGeneratorInt(
      requestedSemesterIdRaw,
      null,
      1,
      Number.MAX_SAFE_INTEGER
    );
    let activeSemester = null;
    if (selectedCourseId && requestedSemesterId) {
      activeSemester = (semesters || []).find((s) => Number(s.id) === requestedSemesterId) || null;
    }
    if (selectedCourseId && !activeSemester) {
      activeSemester = await getActiveSemester(selectedCourseId);
    }
    if (selectedCourseId && !activeSemester && semesters && semesters.length) {
      activeSemester = semesters[0];
    }
    const selectedSemesterId = activeSemester ? Number(activeSemester.id) : null;
    const defaultStartDate = buildSessionGeneratorDefaultStartDate(activeSemester);
    const defaultForm = buildSessionGeneratorFormDefaults({
      activeLocation,
      selectedCourseId,
      selectedSemesterId,
      defaultStartDate,
    });

    if (draftAction === 'new' || !draftRecord) {
      draftRecord = await createSessionGeneratorDraftRecord(userId, defaultForm, []);
      draftEntries = Number.isFinite(userId) && userId > 0
        ? await listSessionGeneratorDraftRecords(userId)
        : [];
    }

    const baseForm = {
      ...defaultForm,
      ...((draftRecord && draftRecord.form) || {}),
      location: activeLocation,
      course_id: selectedCourseId,
      semester_id: selectedSemesterId,
    };
    if (!baseForm.start_date || !isValidDateString(baseForm.start_date)) {
      baseForm.start_date = defaultStartDate;
    }

    const hasFormPayload = hasSessionGeneratorFormPayload(query);
    const draftAssignmentsSeed = draftAction === 'clear'
      ? []
      : normalizeSessionGeneratorDraftAssignments((draftRecord && draftRecord.assignments) || []);
    let form = { ...baseForm };
    if (draftAction === 'clear') {
      form = { ...defaultForm };
    } else if (hasFormPayload) {
      form = {
        ...baseForm,
        location: normalizeGeneratorLocation(query.location || baseForm.location || activeLocation),
        course_id: parseSessionGeneratorInt(query.course_id, baseForm.course_id, 1, Number.MAX_SAFE_INTEGER),
        semester_id: parseSessionGeneratorInt(query.semester_id, baseForm.semester_id, 1, Number.MAX_SAFE_INTEGER),
        window_mode: normalizeSessionWindowMode(query.window_mode || baseForm.window_mode || SESSION_GENERATOR_DEFAULTS.window_mode),
        start_date: isValidDateString(query.start_date) ? String(query.start_date) : (baseForm.start_date || defaultStartDate),
        session_days: parseSessionGeneratorInt(
          query.session_days,
          baseForm.session_days,
          3,
          60
        ),
        session_weeks_count: parseSessionGeneratorInt(
          query.session_weeks_count,
          baseForm.session_weeks_count,
          1,
          12
        ),
        session_weeks_set: String(query.session_weeks_set ?? baseForm.session_weeks_set ?? '').trim(),
        max_events_per_day: parseSessionGeneratorInt(
          query.max_events_per_day,
          baseForm.max_events_per_day,
          1,
          6
        ),
        reserve_every: parseSessionGeneratorInt(
          query.reserve_every,
          baseForm.reserve_every,
          0,
          20
        ),
        exam_gap_days: parseSessionGeneratorInt(
          query.exam_gap_days,
          baseForm.exam_gap_days,
          0,
          5
        ),
        retake_gap_days: parseSessionGeneratorInt(
          query.retake_gap_days,
          baseForm.retake_gap_days,
          1,
          14
        ),
        retake_window_days: parseSessionGeneratorInt(
          query.retake_window_days,
          baseForm.retake_window_days,
          1,
          14
        ),
        include_weekends: hasOwnQueryKey(query, 'include_weekends')
          ? parseSessionGeneratorFlag(query.include_weekends, false)
          : false,
        include_consultations: hasOwnQueryKey(query, 'include_consultations')
          ? parseSessionGeneratorFlag(query.include_consultations, false)
          : false,
        respect_study_days: hasOwnQueryKey(query, 'respect_study_days')
          ? parseSessionGeneratorFlag(query.respect_study_days, false)
          : false,
        day_grouping_mode: normalizeSessionDayGroupingMode(
          query.day_grouping_mode || baseForm.day_grouping_mode || SESSION_GENERATOR_DEFAULTS.day_grouping_mode
        ),
        exam_sequence: normalizeSessionExamSequence(
          query.exam_sequence || baseForm.exam_sequence || SESSION_GENERATOR_DEFAULTS.exam_sequence
        ),
        credit_sequence: normalizeSessionCreditSequence(
          query.credit_sequence || baseForm.credit_sequence || SESSION_GENERATOR_DEFAULTS.credit_sequence
        ),
        strategy: normalizeSessionGeneratorStrategy(query.strategy || baseForm.strategy || SESSION_GENERATOR_DEFAULTS.strategy),
      };
    }

    form.location = activeLocation;
    form.course_id = selectedCourseId;
    form.semester_id = selectedSemesterId;
    form.window_mode = 'weeks';
    form.session_weeks_count = parseSessionGeneratorInt(
      form.session_weeks_count,
      SESSION_GENERATOR_DEFAULTS.session_weeks_count,
      1,
      12
    );
    form.session_weeks_set = String(form.session_weeks_set || '').trim();
    form.day_grouping_mode = normalizeSessionDayGroupingMode(form.day_grouping_mode || SESSION_GENERATOR_DEFAULTS.day_grouping_mode);
    form.exam_sequence = normalizeSessionExamSequence(form.exam_sequence || SESSION_GENERATOR_DEFAULTS.exam_sequence);
    form.credit_sequence = normalizeSessionCreditSequence(form.credit_sequence || SESSION_GENERATOR_DEFAULTS.credit_sequence);
    if (!form.start_date || !isValidDateString(form.start_date)) {
      form.start_date = defaultStartDate;
    }
    if (draftRecord && draftRecord.id) {
      draftRecord = await saveSessionGeneratorDraftRecord(userId, draftRecord.id, {
        form,
        assignments: draftAssignmentsSeed,
      }) || draftRecord;
    }

    let subjects = [];
    let courseStudyDays = [];
    if (selectedCourseId) {
      subjects = await getSubjectsCached(selectedCourseId, { visibleOnly: true });
      try {
        courseStudyDays = await getCourseStudyDays(selectedCourseId);
      } catch (err) {
        courseStudyDays = [];
      }
    }
    const activeStudyDayNames = (courseStudyDays || [])
      .filter((row) => row.is_active)
      .map((row) => row.day_name)
      .filter(Boolean);
    const subjectIds = Array.from(new Set((subjects || [])
      .map((subject) => Number(subject.id))
      .filter((value) => Number.isFinite(value) && value > 0)));
    const teacherMapBySubject = subjectIds.length
      ? await getSessionSubjectTeacherMap(subjectIds)
      : new Map();
    const sessionTeacherMapPayload = serializeSessionTeacherMap(teacherMapBySubject);
    const sessionTeacherFilterOptions = buildSessionTeacherFilterOptions(teacherMapBySubject);

    let gradingRows = [];
    let gradingSource = 'none';
    if (selectedCourseId && selectedSemesterId) {
      try {
        gradingRows = await db.all(
          `
            SELECT subject_id,
                   COALESCE(exam_enabled, 1) AS exam_enabled,
                   COALESCE(credit_enabled, 1) AS credit_enabled,
                   COALESCE(exam_weight_points, 0) AS exam_weight_points,
                   COALESCE(credit_weight_points, 0) AS credit_weight_points
            FROM subject_grading_settings
            WHERE course_id = ? AND semester_id = ?
          `,
          [selectedCourseId, selectedSemesterId]
        );
        gradingSource = 'subject_grading_settings';
      } catch (err) {
        gradingRows = [];
        gradingSource = 'fallback';
      }
    }
    const gradingBySubject = {};
    (gradingRows || []).forEach((row) => {
      gradingBySubject[Number(row.subject_id)] = {
        exam_enabled: Number(row.exam_enabled ?? 1) === 1 ? 1 : 0,
        credit_enabled: Number(row.credit_enabled ?? 1) === 1 ? 1 : 0,
        exam_weight_points: Number(row.exam_weight_points ?? 0) || 0,
        credit_weight_points: Number(row.credit_weight_points ?? 0) || 0,
      };
    });

    let sessionWeekNumbers = [];
    if (form.window_mode === 'weeks' && activeSemester && Number(activeSemester.weeks_count || 0) > 0) {
      const semesterWeeksCount = Number(activeSemester.weeks_count || 0);
      const parsedWeeks = parseWeekSet(form.session_weeks_set, semesterWeeksCount);
      if (parsedWeeks.length) {
        sessionWeekNumbers = parsedWeeks;
      } else {
        const count = Math.min(Math.max(Number(form.session_weeks_count || 1), 1), semesterWeeksCount);
        const startWeek = Math.max(1, semesterWeeksCount - count + 1);
        sessionWeekNumbers = Array.from({ length: count }, (_, idx) => startWeek + idx);
      }
      form.session_weeks_set = sessionWeekNumbers.join(',');
    }
    const explicitSessionDates = form.window_mode === 'weeks'
      ? buildSessionDatesFromWeekNumbers({
          semester: activeSemester,
          weekNumbers: sessionWeekNumbers,
          includeWeekends: form.include_weekends,
          respectStudyDays: form.respect_study_days && activeStudyDayNames.length > 0,
          activeStudyDayNames,
        })
      : [];

    const previewCleared = draftAction === 'clear';
    const preview = null;
    const slotCalendarBuckets = buildSessionDayBuckets({
      startDate: form.start_date,
      sessionDays: form.session_days,
      explicitDates: explicitSessionDates,
      maxEventsPerDay: form.max_events_per_day,
      includeWeekends: form.include_weekends,
      respectStudyDays: form.respect_study_days && activeStudyDayNames.length > 0,
      activeStudyDayNames,
    });

    const slotWeekNumbers = Array.from(new Set((slotCalendarBuckets || [])
      .map((bucket) => getSemesterWeekNumberForDate(bucket.date, activeSemester))
      .filter((week) => Number.isFinite(Number(week)) && Number(week) > 0)))
      .sort((a, b) => a - b);
    let slotScheduleRows = [];
    if (selectedCourseId && selectedSemesterId && slotWeekNumbers.length) {
      try {
        const placeholders = slotWeekNumbers.map(() => '?').join(', ');
        slotScheduleRows = await db.all(
          `
            SELECT se.week_number,
                   se.day_of_week,
                   se.class_number,
                   se.group_number,
                   se.subject_id,
                   COALESCE(se.lesson_type, '') AS lesson_type,
                   s.name AS subject_name
            FROM schedule_entries se
            JOIN subjects s ON s.id = se.subject_id
            WHERE se.course_id = ?
              AND se.semester_id = ?
              AND se.week_number IN (${placeholders})
            ORDER BY se.week_number, se.day_of_week, se.class_number
          `,
          [selectedCourseId, selectedSemesterId, ...slotWeekNumbers]
        );
      } catch (err) {
        slotScheduleRows = [];
      }
    }
    const slotBoard = buildSessionSlotBoard({
      dayBuckets: slotCalendarBuckets,
      semester: activeSemester,
      scheduleRows: slotScheduleRows,
      teacherMapBySubject,
    });
    const subjectById = new Map((subjects || []).map((subject) => [Number(subject.id), subject]));
    const allowedDateSet = new Set((explicitSessionDates || []).filter((date) => isValidDateString(date)));
    const draftAssignmentsRaw = normalizeSessionGeneratorDraftAssignments((draftRecord && draftRecord.assignments) || []);
    const manualAssignmentsInitial = draftAssignmentsRaw
      .map((item) => {
        const subjectId = Number(item.subject_id);
        const subject = subjectById.get(subjectId);
        if (!subject) return null;
        const date = toDateOnly(item.date);
        if (!isValidDateString(date)) return null;
        if (allowedDateSet.size && !allowedDateSet.has(date)) return null;
        const classNumber = Number(item.class_number);
        if (!Number.isFinite(classNumber) || classNumber < 1 || classNumber > 7) return null;
        const groupCount = Math.max(1, Number(subject.group_count || 1));
        const groupNumberRaw = Number(item.group_number || 0);
        const groupNumber = Number.isFinite(groupNumberRaw) && groupNumberRaw > 0
          ? Math.floor(groupNumberRaw)
          : null;
        if (groupNumber && groupNumber > groupCount) return null;
        return {
          subject_id: subjectId,
          type: item.type === 'credit'
            ? 'credit'
            : (item.type === 'consultation' ? 'consultation' : 'exam'),
          date,
          class_number: classNumber,
          group_number: groupNumber,
          note: item.note ? String(item.note).slice(0, 255) : '',
        };
      })
      .filter(Boolean);
    if (
      draftRecord
      && draftRecord.id
      && JSON.stringify(draftAssignmentsRaw) !== JSON.stringify(manualAssignmentsInitial)
    ) {
      draftRecord = await saveSessionGeneratorDraftRecord(userId, draftRecord.id, {
        form,
        assignments: manualAssignmentsInitial,
      }) || draftRecord;
    }
    const plannerItems = [];

    const selectedCourse = selectedCourseId ? await getCourseById(selectedCourseId) : null;
    const uiHints = [];
    if (draftAction === 'new') {
      uiHints.push(`Створено новий план генератора сесій #${draftRecord ? draftRecord.id : '—'}.`);
    }
    if (previewCleared) {
      uiHints.push(`План #${draftRecord ? draftRecord.id : '—'} очищено до базових параметрів.`);
    }
    if (!selectedSemesterId) {
      uiHints.push('Активний семестр не знайдено. Сесійні слоти формуються в fallback-режимі за датою старту.');
    }
    if (form.respect_study_days && !activeStudyDayNames.length) {
      uiHints.push('Активні навчальні дні курсу не задані — фільтр по навчальних днях не застосовано.');
    }
    if (form.window_mode === 'weeks' && !activeSemester) {
      uiHints.push('Режим "сесійні тижні" потребує активного семестру з датою старту. Зараз використано звичайний режим за днями.');
    }

    draftEntries = Number.isFinite(userId) && userId > 0
      ? await listSessionGeneratorDraftRecords(userId)
      : [];
    const draftMeta = draftRecord
      ? {
          id: Number(draftRecord.id),
          created_at: draftRecord.created_at || null,
          updated_at: draftRecord.updated_at || null,
          total: (draftEntries || []).length,
          list: (draftEntries || []).map((item) => ({
            id: Number(item.id),
            updated_at: item.updated_at || null,
          })),
        }
      : null;

    return res.render('admin-session-generator', {
      username: req.session.user.username,
      role: req.session.role,
      activeLocation,
      coursesByLocation,
      selectedCourse,
      selectedCourseId,
      subjects,
      semesters,
      activeSemester,
      selectedSemesterId,
      form,
      preview,
      previewCleared,
      uiHints,
      gradingSource,
      courseStudyDays,
      activeStudyDayNames,
      sessionWeekNumbers,
      slotBoard,
      plannerItems,
      draftMeta,
      manualAssignmentsInitial,
      sessionTeacherFilterOptions,
      sessionTeacherMapPayload,
      sessionMarkLegend: SESSION_GENERATOR_MARK_LEGEND,
      strategyOptions: [
        { value: 'exams_first', label: 'Екзамени спочатку' },
        { value: 'balanced', label: 'Змішано' },
        { value: 'credits_first', label: 'Заліки спочатку' },
      ],
      sessionWindowOptions: [
        { value: 'days', label: 'Дні (від дати старту)' },
        { value: 'weeks', label: 'Сесійні тижні семестру' },
      ],
      sessionGroupingOptions: [
        { value: 'none', label: 'Без обмеження по днях' },
        { value: 'subject_per_day', label: 'Один предмет на день' },
        { value: 'activity_per_day', label: 'Один тип активності на день' },
      ],
      examSequenceOptions: [
        { value: 'exam_only', label: 'Лише екзамен' },
        { value: 'consult_exam', label: 'Консультація + екзамен' },
        { value: 'consult_exam_credit', label: 'Консультація + екзамен + залік' },
      ],
      creditSequenceOptions: [
        { value: 'credit_only', label: 'Лише залік (мінімум)' },
        { value: 'consult_credit', label: 'Консультація + залік' },
      ],
    });
  } catch (err) {
    return handleDbError(res, err, 'admin.sessionGenerator.render');
  }
});

